    SourceStratagemActivationProfile('phase17s:stratagem:adeptus-custodes:auric-champions:000008931006', 'stratagem:adeptus-custodes:auric-champions:000008931006', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:adeptus-custodes:auric-champions:000008931006', 'adeptus-custodes', 'auric-champions', '000008931006', 'VIGIL UNENDING', 2, 'epic_deed', 'Fight phase.', 'One Adeptus Custodes Character model from your army that was just destroyed and has not fought this phase. You can use this Stratagem on that unit even though it was just destroyed.', 'Do not remove your destroyed model from play. The destroyed model can fight after the attacking unit has finished making attacks, and is then removed from play.', 'matched play same stratagem per phase', 'start_phase', ('fight',), 'friendly_unit', 'friendly_unit', ('CHARACTER',), (), (), (), (), '7282e9c73ad5fd5fb222d135c8d8e2387123e7849ad4ed13b75ced3dc0ac71ea'),
