    SourceStratagemActivationProfile('phase17s:stratagem:adeptus-mechanicus:skitarii-hunter-cohort:000008561007', 'stratagem:adeptus-mechanicus:skitarii-hunter-cohort:000008561007', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:adeptus-mechanicus:skitarii-hunter-cohort:000008561007', 'adeptus-mechanicus', 'skitarii-hunter-cohort', '000008561007', 'PROGRAMMED WITHDRAWAL', 1, 'strategic_ploy', "End of your opponent's Fight phase.", 'Up to two SICARIAN units from your army, or one SKITARII INFANTRY or SKITARII MOUNTED unit from your army.', 'Remove those units from the battlefield and place them into Strategic Reserves. RESTRICTIONS: Each unit targeted with this Stratagem must be more than 3" away from all enemy units.', 'matched play same stratagem per phase', 'end_phase', ('fight',), 'friendly_unit', 'friendly_unit', ('INFANTRY', 'MOUNTED',), (), (), (), (), 'b344d620fc049a967402a5213cacbee5c1213bad167058cb86b6938384d0fae5'),
    SourceStratagemActivationProfile('phase17s:stratagem:aeldari:armoured-warhost:000009770002', 'stratagem:aeldari:armoured-warhost:000009770002', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:aeldari:armoured-warhost:000009770002', 'aeldari', 'armoured-warhost', '000009770002', 'LAYERED WARDS', 1, 'strategic_ploy', 'Any phase, just after a mortal wound is allocated to an AELDARI VEHICLE unit from your army.', 'That Aeldari Vehicle unit.', 'Until the end of the phase, models in your unit have the Feel No Pain 5+ ability against mortal wounds.', 'matched play same stratagem per phase', 'start_phase', ('any',), 'friendly_unit', 'friendly_unit', ('VEHICLE',), (), (), (), (), '8cdd4ad58bd4683ab42b81fd556ed10776b513a0d121136a17a349512a4a0924'),
    SourceStratagemActivationProfile('phase17s:stratagem:aeldari:armoured-warhost:000009770003', 'stratagem:aeldari:armoured-warhost:000009770003', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:aeldari:armoured-warhost:000009770003', 'aeldari', 'armoured-warhost', '000009770003', 'SWIFT DEPLOYMENT', 1, 'strategic_ploy', 'Your Movement phase.', 'One Aeldari Transport unit from your army.', 'Until the end of the phase, units can disembark from your TRANSPORT after it has Advanced. Units that do so count as having made a Normal move that phase, and cannot declare a charge in the same turn, but can otherwise act normally.', 'matched play same stratagem per phase', 'start_phase', ('movement',), 'friendly_unit', 'friendly_unit', ('TRANSPORT',), (), (), (), (), '996d07becbf2e3a03be91d9db5f248af010f4ece2c5b0c1020b9515bf5c39c38'),
    SourceStratagemActivationProfile('phase17s:stratagem:aeldari:armoured-warhost:000009770004', 'stratagem:aeldari:armoured-warhost:000009770004', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:aeldari:armoured-warhost:000009770004', 'aeldari', 'armoured-warhost', '000009770004', 'VECTORED ENGINES', 1, 'strategic_ploy', 'Your Movement phase, just after an AELDARI VEHICLE unit from your army that can FLY Falls Back.', 'That Aeldari Fly Vehicle unit.', 'Until the end of the turn, your unit is eligible to shoot in a turn in which it Fell Back.', 'matched play same stratagem per phase', 'start_phase', ('movement',), 'friendly_unit', 'friendly_unit', ('FLY', 'VEHICLE',), (), (), (), (), '731d422e3bf69b5a23924585b64ab6e21ea25270924a30d2ed431374c16f337a'),
    SourceStratagemActivationProfile('phase17s:stratagem:aeldari:armoured-warhost:000009770005', 'stratagem:aeldari:armoured-warhost:000009770005', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:aeldari:armoured-warhost:000009770005', 'aeldari', 'armoured-warhost', '000009770005', 'CLOUDSTRIKE', 1, 'strategic_ploy', 'Start of the Reinforcements step of your Movement phase.', 'One Aeldari Vehicle unit from your army that can Fly and is in Strategic Reserves.', 'Until the end of the phase, your unit has the Deep Strike ability. When your unit is set up on the battlefield using the Deep Strike ability, it can be set up anywhere on the battlefield that is more than 6" horizontally away from all enemy units, but if it does, until the end of the turn, it is not eligible to declare a charge. In addition, if your unit is a Transport, each unit that disembarks from it this turn must be set up more than 6" horizontally from all enemy units and until the end of the turn, is not eligible to declare a charge.', 'matched play same stratagem per phase', 'start_phase', ('movement',), 'friendly_unit', 'friendly_unit', ('FLY', 'VEHICLE',), (), (), (), (), '8918db5876de73a0f3b7575baaba7d905425b04f57542925eea925203c405046'),
    SourceStratagemActivationProfile('phase17s:stratagem:aeldari:armoured-warhost:000009770006', 'stratagem:aeldari:armoured-warhost:000009770006', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:aeldari:armoured-warhost:000009770006', 'aeldari', 'armoured-warhost', '000009770006', 'SOULSIGHT', 1, 'strategic_ploy', 'Your Shooting phase.', 'One Aeldari Vehicle unit from your army that has not been selected to shoot this phase.', 'Until the end of the phase, each time your unit is selected to shoot, you can re-roll one Hit roll, one Wound roll and one Damage roll made for a model in your unit. If you are using fast dice rolling, you can select one of those rolls to re-roll before moving onto the next step of the attack sequence.', 'matched play same stratagem per phase', 'start_phase', ('shooting',), 'friendly_unit', 'not_selected_to_shoot_unit', ('VEHICLE',), (), (), (), (), 'd7aa2303e24eafd88342079c3d7bb782e3ad2c1ee4b019ca8a30bae5aac4f1fb'),
    SourceStratagemActivationProfile('phase17s:stratagem:aeldari:armoured-warhost:000009770007', 'stratagem:aeldari:armoured-warhost:000009770007', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:aeldari:armoured-warhost:000009770007', 'aeldari', 'armoured-warhost', '000009770007', 'ANTI\u2011GRAV REPULSION', 1, 'strategic_ploy', "Your opponent's Charge phase, just after an enemy unit has declared a charge.", 'One Aeldari Vehicle unit from your army that can Fly and was selected as a target of that charge.', 'Until the end of the phase, subtract 2 from Charge rolls made for that enemy unit.', 'matched play same stratagem per phase', 'start_phase', ('charge',), 'friendly_unit', 'friendly_unit', ('FLY', 'VEHICLE',), (), (), (), (), '1dbf353609833a815c6bba3ee0dab6f9f2699d6c683ca25b3e12d24fe58f7ddc'),
