    SourceStratagemActivationProfile('phase17s:stratagem:aeldari:aspect-host:000009928003', 'stratagem:aeldari:aspect-host:000009928003', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:aeldari:aspect-host:000009928003', 'aeldari', 'aspect-host', '000009928003', 'TO THEIR FINAL BREATH', 1, 'strategic_ploy', 'Fight phase, just after an enemy unit has selected its targets.', "One Aspect Warriors or Avatar of Khaine unit from your army that was selected as the target of one or more of the attacking unit's attacks.", 'Each time you use this Stratagem, you can remove one Aspect Shrine token your unit has (see datasheets). Then, until the end of the phase, each time a model in your unit is destroyed, if that model has not fought this phase, roll one D6, adding 1 to the result if you removed an Aspect Shrine token during this usage of this Stratagem. On a 4+, do not remove the destroyed model from play; it can fight after the attacking unit has finished making its attacks, and is then removed from play.', 'matched play same stratagem per phase', 'after_unit_selected_as_target', ('fight',), 'friendly_unit', 'selected_target_unit', (), (), (), (), (), '3179f13ac19e07651b1ac22e028c9613e7f0fa69c50988fe5e58b5063574e884'),
    SourceStratagemActivationProfile('phase17s:stratagem:aeldari:aspect-host:000009928004', 'stratagem:aeldari:aspect-host:000009928004', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:aeldari:aspect-host:000009928004', 'aeldari', 'aspect-host', '000009928004', 'SKYBORNE SANCTUARY', 1, 'strategic_ploy', 'End of the Fight phase.', 'One Asuryani unit from your army that was eligible to fight this phase and one friendly Transport it is able to embark within.', 'If your ASURYANI unit is not within Engagement Range of one or more enemy units and is wholly within 6" of that TRANSPORT, it can embark within it.', 'matched play same stratagem per phase', 'end_phase', ('fight',), 'friendly_unit', 'friendly_unit', ('TRANSPORT',), (), (), (), (), '02f2da64c68769ca8d2b3ee6be3148daa754abb838b49f3445c24cd991bbf58e'),
    SourceStratagemActivationProfile('phase17s:stratagem:aeldari:aspect-host:000009928005', 'stratagem:aeldari:aspect-host:000009928005', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:aeldari:aspect-host:000009928005', 'aeldari', 'aspect-host', '000009928005', 'DOOM INESCAPABLE', 1, 'battle_tactic', 'Your Shooting phase.', 'One Avatar of Khaine model from your army that has not been selected to shoot this phase.', 'Until the end of the phase, your model\'s Wailing Doom ranged weapon has a Range characteristic of 18" and a Damage characteristic of 8.', 'matched play same stratagem per phase', 'start_phase', ('shooting',), 'friendly_unit', 'not_selected_to_shoot_unit', (), (), (), (), (), 'd502ea476d036972f8395fa26e56b09bbcfcf160bca3aa04450a41da9ba9681e'),
    SourceStratagemActivationProfile('phase17s:stratagem:aeldari:aspect-host:000009928006', 'stratagem:aeldari:aspect-host:000009928006', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:aeldari:aspect-host:000009928006', 'aeldari', 'aspect-host', '000009928006', 'PRETERNATURAL PRECISION', 1, 'battle_tactic', 'Your Shooting phase.', 'One Aspect Warriors unit from your army that has not been selected to shoot this phase.', 'Each time you use this Stratagem, you can remove one Aspect Shrine token your unit has (see datasheets). Then, select one of the following abilities, or select two of the following abilities if you removed an Aspect Shrine token during this usage of this Stratagem: [IGNORES COVER], [LETHAL HITS], [SUSTAINED HITS 1]. Until the end of the phase, ranged weapons equipped by models in your unit have the selected abilities.', 'matched play same stratagem per phase', 'start_phase', ('shooting',), 'friendly_unit', 'not_selected_to_shoot_unit', (), (), (), (), (), 'cc0f7da93d3ed78f30c9cd5a57e43371d60c3bdb1f1d87039745153ba792679f'),
    SourceStratagemActivationProfile('phase17s:stratagem:aeldari:aspect-host:000009928007', 'stratagem:aeldari:aspect-host:000009928007', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:aeldari:aspect-host:000009928007', 'aeldari', 'aspect-host', '000009928007', 'KHAINE\u2019S VENGEANCE', 1, 'strategic_ploy', "Your opponent's Movement phase, just after an enemy unit (excluding MONSTERS and VEHICLES) is selected to Fall Back.", 'One Aspect Warriors or Avatar of Khaine unit from your army that is within Engagement Range of that enemy unit.', 'All models in that enemy unit must take a Desperate Escape test. When doing so, if that enemy unit is Battle-shocked, subtract 1 from each of those tests.', 'matched play same stratagem per phase', 'just_after_enemy_unit_selected_to_fall_back', ('movement',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), '2c67c1ed18970665b94387a1d560dacd738cd60e2854302134de3d0c6720ff13'),
    SourceStratagemActivationProfile('phase17s:stratagem:aeldari:devoted-of-ynnead:000009920002', 'stratagem:aeldari:devoted-of-ynnead:000009920002', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:aeldari:devoted-of-ynnead:000009920002', 'aeldari', 'devoted-of-ynnead', '000009920002', 'PALL OF DREAD', 1, 'strategic_ploy', 'Any phase.', 'One Ynnari unit from your army that was just destroyed while it was within range of one or more objective markers you controlled at the end of the previous phase. You can use this Stratagem on that unit even though it was just destroyed.', "Select one of those objective markers. That objective marker remains under your control until your opponent's Level of Control over that objective marker is greater than yours at the end of a phase.", 'matched play same stratagem per phase', 'start_phase', ('any',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), 'e055407406ee1258dec8d1886bce1a9c431176ec21072a239f927ba002e2b41f'),
