    SourceStratagemActivationProfile('phase17s:stratagem:chaos-daemons:plague-legion:000009820007', 'stratagem:chaos-daemons:plague-legion:000009820007', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:chaos-daemons:plague-legion:000009820007', 'chaos-daemons', 'plague-legion', '000009820007', 'PLAGUE OF WOES', 1, 'strategic_ploy', "Your opponent's Command phase, before selecting any targets for the Melancholic Miasma Detachment rule.", 'One Legiones Daemonica Nurgle unit from your army.', 'Until the end of the phase, after an enemy unit takes a Battle-shock test as a result of the Melancholic Miasma Detachment rule, select one other enemy unit within 9" of your unit; that enemy unit must take a Battle-shock test.', 'matched play same stratagem per phase', 'start_phase', ('command',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), '28dbc9953f61b2c554e828c5d05401946cb5440f4b794e8428752f6a46300ffc'),
    SourceStratagemActivationProfile('phase17s:stratagem:chaos-daemons:scintillating-legion:000009811002', 'stratagem:chaos-daemons:scintillating-legion:000009811002', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:chaos-daemons:scintillating-legion:000009811002', 'chaos-daemons', 'scintillating-legion', '000009811002', 'IMPOSSIBLE ECLIPSE', 1, 'strategic_ploy', 'Any phase.', 'One Legiones Daemonica Tzeentch Monster unit from your army that is on the battlefield.', "Select No Man's Land or your opponent's deployment zone, or spend one Flux token and select both. Until the end of the phase, the selected areas of the battlefield are within your army's Shadow of Chaos.", 'matched play same stratagem per phase', 'start_phase', ('any',), 'friendly_unit', 'friendly_unit', ('MONSTER',), (), (), (), (), 'b82426cafd7aab75c883da66dfb177c809e9b49346fa3efd7e687fdd451a9a0a'),
    SourceStratagemActivationProfile('phase17s:stratagem:chaos-daemons:scintillating-legion:000009811003', 'stratagem:chaos-daemons:scintillating-legion:000009811003', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:chaos-daemons:scintillating-legion:000009811003', 'chaos-daemons', 'scintillating-legion', '000009811003', 'PYROGENESIS', 1, 'battle_tactic', 'Your Shooting phase or the Fight phase.', 'One Legiones Daemonica Tzeentch unit from your army that has not been selected to shoot or fight that phase.', 'Until the end of the phase, add 2 to the Strength characteristic of weapons equipped by models in your unit, or spend one Flux token and add 3 to the Strength characteristic of those weapons and improve the Armour Penetration characteristic of those weapons by 1 instead.', 'matched play same stratagem per phase', 'start_phase', ('shooting', 'fight',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), 'bddc7b27a76980c741fb3ee411db89cb5da13eee64f919d57b4d35ff8423918f'),
    SourceStratagemActivationProfile('phase17s:stratagem:chaos-daemons:scintillating-legion:000009811004', 'stratagem:chaos-daemons:scintillating-legion:000009811004', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:chaos-daemons:scintillating-legion:000009811004', 'chaos-daemons', 'scintillating-legion', '000009811004', 'FLICKERING REALITY', 1, 'strategic_ploy', 'Fight phase, just after an enemy unit has selected its targets.', "One Legiones Daemonica Tzeentch unit from your army that was selected as the target of one or more of the attacking unit's attacks.", 'Roll one D6, then you can spend one Flux token to re-roll the result: until the end of the phase, each time an attack targets your unit, on an unmodified Hit roll (after any re-roll) of that result, the attack sequence ends, even if the original Hit roll would have been a Critical Hit. Example: If you roll a 2 and choose to spend one Flux token to re-roll the result, and the re-roll is a 6, then until the end of the phase, each time an attack targets your unit, on an unmodified Hit roll of 6 the attack sequence ends, that attack fails to hit and no Critical Hit effects (e.g. Lethal Hits) are resolved.', 'matched play same stratagem per phase', 'after_unit_selected_as_target', ('charge',), 'friendly_unit', 'selected_target_unit', (), (), (), (), (), '0f7d0392ff4523eaa17dc1960348cb66dff93d6b5a8c44c4ed10dee7dae96073'),
    SourceStratagemActivationProfile('phase17s:stratagem:chaos-daemons:scintillating-legion:000009811005', 'stratagem:chaos-daemons:scintillating-legion:000009811005', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:chaos-daemons:scintillating-legion:000009811005', 'chaos-daemons', 'scintillating-legion', '000009811005', 'FATEBORNE NIGHTMARES', 1, 'strategic_ploy', 'Your Movement phase or your Charge phase.', 'One Legiones Daemonica Tzeentch unit from your army.', 'Until the end of the phase, each time a model in your unit makes a move, it can move through terrain features.', 'matched play same stratagem per phase', 'start_phase', ('movement', 'charge',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), '6bd39dc52659a802167c860ec2ec1f332c9c52b22e7c777d1826c425de53b5f5'),
    SourceStratagemActivationProfile('phase17s:stratagem:chaos-daemons:scintillating-legion:000009811006', 'stratagem:chaos-daemons:scintillating-legion:000009811006', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:chaos-daemons:scintillating-legion:000009811006', 'chaos-daemons', 'scintillating-legion', '000009811006', 'FICKLEFIRE', 1, 'strategic_ploy', 'Your Shooting phase.', 'One Legiones Daemonica Tzeentch unit from your army that is within Engagement Range of one or more enemy units.', 'Until the end of the phase, enemy units are not considered to be within Engagement Range of your unit for the purposes of selecting targets for, and resolving attacks with, ranged weapons. Until the end of the phase, each time an enemy model is destroyed while its unit is within Engagement Range of your unit, roll one D6: on a 5+, your unit suffers 1 mortal wound after the attacking unit has finished making its attacks.', 'matched play same stratagem per phase', 'start_phase', ('shooting',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), 'de506f98204aa7a04fc3922d5c22424a421b64880b873388acb3f70ee54544b9'),
