    SourceStratagemActivationProfile('phase17s:stratagem:chaos-daemons:shadow-legion:000009979002', 'stratagem:chaos-daemons:shadow-legion:000009979002', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:chaos-daemons:shadow-legion:000009979002', 'chaos-daemons', 'shadow-legion', '000009979002', 'SPITEFUL DEMISE', 1, 'strategic_ploy', 'Any phase, just after a Shadow Legion unit from your army is destroyed, before removing the last model in that unit from the battlefield and before rolling any dice for the Deadly Demise ability.', 'That SHADOW LEGION unit. You can use this Stratagem on that unit even though it was just destroyed.', 'Roll one D6 for each enemy unit that is within Engagement Range of the last model in your unit, adding 2 to the result if your unit has the Slaanesh keyword: on a 4-5, that enemy unit suffers D3 mortal wounds; on a 6+, that enemy unit suffers 3 mortal wounds.', 'matched play same stratagem per phase', 'start_phase', ('any',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), 'a8f0b2db1b90c071a472b490082c442cfec376213318ab56b174eed7f4224c63'),
    SourceStratagemActivationProfile('phase17s:stratagem:chaos-daemons:shadow-legion:000009979003', 'stratagem:chaos-daemons:shadow-legion:000009979003', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:chaos-daemons:shadow-legion:000009979003', 'chaos-daemons', 'shadow-legion', '000009979003', 'CHANNELLED WRATH', 1, 'strategic_ploy', 'Fight phase.', 'One Shadow Legion unit from your army that has not been selected to fight this phase.', 'Until the end of the phase, melee weapons equipped by models in your unit have the [LANCE] ability. If your unit has the Khorne keyword, until the end of the phase, improve the Armour Penetration characteristic of those weapons by 1 as well.', 'matched play same stratagem per phase', 'start_phase', ('fight',), 'friendly_unit', 'not_selected_to_fight_unit', (), (), (), (), (), '01d88e1882a041ccf957ba8a18ff9447720a4d299640d4d44122e097384a58e0'),
