    SourceStratagemActivationProfile('phase17s:stratagem:chaos-daemons:shadow-legion:000009979005', 'stratagem:chaos-daemons:shadow-legion:000009979005', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:chaos-daemons:shadow-legion:000009979005', 'chaos-daemons', 'shadow-legion', '000009979005', 'ENCROACHING DARKNESS', 1, 'battle_tactic', 'Your Shooting phase.', 'Up to one Shadow Legion Heretic Astartes unit from your army and up to one Shadow Legion Legiones Daemonica unit from your army. You can only select units that arrived from Reserves this turn.', 'Until the end of the phase, weapons equipped by models in your selected units have the [IGNORES COVER] ability.', 'matched play same stratagem per phase', 'start_phase', ('shooting',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), 'a2e297b74d6d78bf90d95e102902b226371daeab68a201d9b0d078f36d8de01b'),
