    SourceStratagemActivationProfile('phase17s:stratagem:chaos-knights:helhunt-lance:000010752003', 'stratagem:chaos-knights:helhunt-lance:000010752003', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:chaos-knights:helhunt-lance:000010752003', 'chaos-knights', 'helhunt-lance', '000010752003', 'MERCILESS FUSILLADE', 1, 'battle_tactic', 'Start of your Shooting phase or the start of the Fight phase.', 'One Titanic Chaos Knights unit from your army, and up to two friendly War Dog units, that have not been selected to shoot or fight this phase.', 'Select one enemy unit that is an eligible target for each of those CHAOS KNIGHTS units. Until the end of the phase, each time one of those Chaos Knights units is selected to shoot or fight, if that enemy unit is an eligible target, you can only select that enemy unit as the target for all of those attacks and those attacks have the [SUSTAINED HITS 1] ability.', 'matched play same stratagem per phase', 'start_phase', ('shooting', 'fight',), 'friendly_unit', 'friendly_unit', ('TITANIC',), (), (), (), (), '0f23ebb0d2f550647c72d03727c4e175fbaff9558745fc17a9f420d26ddaff03'),
    SourceStratagemActivationProfile('phase17s:stratagem:chaos-knights:helhunt-lance:000010752004', 'stratagem:chaos-knights:helhunt-lance:000010752004', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:chaos-knights:helhunt-lance:000010752004', 'chaos-knights', 'helhunt-lance', '000010752004', 'BEASTHIDE MANIFESTATION', 1, 'battle_tactic', "Your opponent's Shooting phase or the Fight phase, just after an enemy unit has selected its targets.", "One CHAOS KNIGHTS unit from your army that was selected as the target of one or more of the attacking unit's attacks.", 'Until the attacking unit has finished making its attacks, each time an attack targets your unit, worsen the Armour Penetration characteristic of that attack by 1.', 'matched play same stratagem per phase', 'after_unit_selected_as_target', ('shooting', 'fight',), 'friendly_unit', 'selected_target_unit', (), (), (), (), (), 'f862b6e692f94bbc0f1d2a3a1c15c1dbd7ce260b1af8e0c869937c6158459cbf'),
    SourceStratagemActivationProfile('phase17s:stratagem:chaos-knights:helhunt-lance:000010752005', 'stratagem:chaos-knights:helhunt-lance:000010752005', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:chaos-knights:helhunt-lance:000010752005', 'chaos-knights', 'helhunt-lance', '000010752005', 'FLUSH THE QUARRY', 1, 'battle_tactic', 'Start of your Movement phase.', 'One Titanic Chaos Knights unit from your army and up to three friendly War Dog units within 6" of that Titanic Chaos Knights unit.', 'Until the end of the phase, each time one of those War Dog units makes a Normal, Advance or Fall Back move, its models can move through models and terrain features. When doing so, they can move within Engagement Range of such models but cannot end that move within Engagement Range of them, and any Desperate Escape test is automatically passed.', 'matched play same stratagem per phase', 'start_phase', ('movement',), 'friendly_unit', 'friendly_unit', ('TITANIC',), (), (), (), (), '3bd85a7c0fc054d40355d134c04570d17f6e349288148eae15164029e3da714c'),
    SourceStratagemActivationProfile('phase17s:stratagem:chaos-knights:helhunt-lance:000010752006', 'stratagem:chaos-knights:helhunt-lance:000010752006', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:chaos-knights:helhunt-lance:000010752006', 'chaos-knights', 'helhunt-lance', '000010752006', 'CONTEMPTUOUS VOLLEYS', 1, 'strategic_ploy', 'Your Movement phase, just after a CHAOS KNIGHTS unit from your army Falls Back.', 'That Chaos Knights unit.', 'Until the end of the turn, your unit is eligible to shoot and declare a charge in a turn in which it Fell Back.', 'matched play same stratagem per phase', 'start_phase', ('movement',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), '9294cdcd812d14ae30b0cc463db816f83b8f1775586635e66e8d2d94c72123ca'),
    SourceStratagemActivationProfile('phase17s:stratagem:chaos-knights:helhunt-lance:000010752007', 'stratagem:chaos-knights:helhunt-lance:000010752007', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:chaos-knights:helhunt-lance:000010752007', 'chaos-knights', 'helhunt-lance', '000010752007', 'GOADED BEAST', 1, 'strategic_ploy', "Your opponent's Shooting phase, just after an enemy unit has shot.", 'One CHAOS KNIGHTS unit from your army that lost one or more wounds as a result of those attacks.', 'Your unit can make a Surge move. To do so, roll one D6: models in your unit move a number of inches up to the result, but your unit must end that move as close as possible to the closest enemy unit (excluding AIRCRAFT). When doing so, those models can be moved within Engagement Range of that enemy unit.', 'matched play same stratagem per phase', 'just_after_enemy_unit_has_shot', ('shooting',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), 'cd03f543bea646dacec64bf0ef9abd8e0d118897feb5e171704cb5afee3a7b3e'),
    SourceStratagemActivationProfile('phase17s:stratagem:chaos-knights:houndpack-lance:000010313002', 'stratagem:chaos-knights:houndpack-lance:000010313002', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:chaos-knights:houndpack-lance:000010313002', 'chaos-knights', 'houndpack-lance', '000010313002', 'VOX-HOWL', 2, 'battle_tactic', 'Start of the Shooting phase or the start of the Fight phase.', 'One War Dog Character unit from your army.', 'Each enemy unit within 6" of your unit must take a Battle-shock test. Each friendly WAR DOG unit that is within 6" of your unit and is Battle-shocked must take a Leadership test; if that test is passed, that unit is no longer Battle-shocked. RESTRICTIONS: You can only use this Stratagem once per turn.', 'matched play same stratagem per phase', 'start_phase', ('shooting', 'fight',), 'friendly_unit', 'friendly_unit', ('CHARACTER',), (), (), (), (), 'f33a4c8a1ed2b8f66aae6075f9ae0d24f932bf09dfa9995cc02f43bd393d143e'),
    SourceStratagemActivationProfile('phase17s:stratagem:chaos-knights:houndpack-lance:000010313003', 'stratagem:chaos-knights:houndpack-lance:000010313003', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:chaos-knights:houndpack-lance:000010313003', 'chaos-knights', 'houndpack-lance', '000010313003', 'HUNGRY FOR COMBAT', 1, 'battle_tactic', 'Start of the Fight phase.', 'Two or more War Dog units from your army within Engagement Range of the same enemy unit.', 'Select one enemy unit within Engagement Range of those WAR DOG units. Until the end of the phase, models in those WAR DOG units can only target that enemy unit, but each time a model in one of those WAR DOG units makes an attack, an unmodified Hit roll of 5+ scores a Critical Hit.', 'matched play same stratagem per phase', 'start_phase', ('fight',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), '655fd17c813a414f397e73bd1004ed197dcdc187ace00e121a0cb195e0044154'),
    SourceStratagemActivationProfile('phase17s:stratagem:chaos-knights:houndpack-lance:000010313004', 'stratagem:chaos-knights:houndpack-lance:000010313004', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:chaos-knights:houndpack-lance:000010313004', 'chaos-knights', 'houndpack-lance', '000010313004', 'CUNNING HUNTER', 1, 'strategic_ploy', 'Your Movement phase, just after a War Dog unit from your army Falls Back.', 'That WAR DOG unit.', 'Until the end of the turn, your unit is eligible to shoot and declare a charge in a turn in which it Fell Back.', 'matched play same stratagem per phase', 'start_phase', ('movement',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), '55cefd336424864b8d3b220ca5a432171630aade39a735bd60df1c1d5bf29d2f'),
    SourceStratagemActivationProfile('phase17s:stratagem:chaos-knights:houndpack-lance:000010313005', 'stratagem:chaos-knights:houndpack-lance:000010313005', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:chaos-knights:houndpack-lance:000010313005', 'chaos-knights', 'houndpack-lance', '000010313005', 'ANIMALISTIC RAGE', 1, 'battle_tactic', "Your opponent's Shooting phase or the Fight phase, just after a War Dog unit from your army that has not yet fought is destroyed.", 'That WAR DOG unit. You can use this Stratagem on that unit even though it was just destroyed.', "Before resolving your unit's Deadly Demise ability, it can either shoot or fight. When doing so, it must target only the enemy unit that just destroyed it, and can only do so if that enemy unit is an eligible target. After it has done so and after any Consolidation moves have been made, resolve your unit's Deadly Demise ability as normal.", 'matched play same stratagem per phase', 'start_phase', ('shooting', 'fight',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), 'c9ec70791a6f2d2accf41aabdb15f6d1a8a3c45c8295850fdc54eb9d78177cec'),
