    SourceStratagemActivationProfile('phase17s:stratagem:chaos-knights:iconoclast-fiefdom:000009766003', 'stratagem:chaos-knights:iconoclast-fiefdom:000009766003', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:chaos-knights:iconoclast-fiefdom:000009766003', 'chaos-knights', 'iconoclast-fiefdom', '000009766003', 'WRETCHED MASSES', 2, 'battle_tactic', 'Any phase.', 'One Damned unit (excluding Accursed Cultists) from your army that was just destroyed. You can use this Stratagem on that unit even though it was just destroyed.', 'Add a new unit to your army identical to your destroyed unit, in Strategic Reserves, at its Starting Strength and with all of its wounds remaining. RESTRICTIONS: You can only use this Stratagem once per battle. This Stratagem cannot be used to return destroyed CHARACTER units to Attached units.', 'matched play same stratagem per phase', 'start_phase', ('any',), 'friendly_unit', 'friendly_unit', (), (), (), ('ACCURSED CULTISTS',), (), '9358a9d8fd6c3d3c7e4658760be469da88d657907a147f2321f0e622423fc8f7'),
    SourceStratagemActivationProfile('phase17s:stratagem:chaos-knights:iconoclast-fiefdom:000009766004', 'stratagem:chaos-knights:iconoclast-fiefdom:000009766004', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:chaos-knights:iconoclast-fiefdom:000009766004', 'chaos-knights', 'iconoclast-fiefdom', '000009766004', 'SOUL HUNGER', 1, 'battle_tactic', 'Fight phase, just after a CHAOS KNIGHTS unit from your army has fought.', 'That Chaos Knights unit.', 'If one or more models were destroyed as a result of those attacks, your unit regains up to D3 lost wounds. If one or more models from Battle-shocked units were destroyed as a result of those attacks, your unit regains up to D3+2 lost wounds instead.', 'matched play same stratagem per phase', 'start_phase', ('fight',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), '05bc7554d785d4bb6a220a57b984063a29645ba9e81b192c64a89276eb45737d'),
