    SourceStratagemActivationProfile('phase17s:stratagem:chaos-knights:traitoris-lance:000008517006', 'stratagem:chaos-knights:traitoris-lance:000008517006', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:chaos-knights:traitoris-lance:000008517006', 'chaos-knights', 'traitoris-lance', '000008517006', 'IMPERIOUS ADVANCE', 1, 'epic_deed', 'Your Movement phase or your Charge phase.', 'Up to two War Dog units from your army or one Titanic Chaos Knights unit from your army.', 'Until the end of the phase, each time a model in one of your units makes a Normal, Advance, Fall Back or Charge move, it can move through models and terrain features. When doing so, it can move within Engagement Range of such models but, unless it made a Charge move, cannot end that move within Engagement Range of them, and any Desperate Escape test is automatically passed (the Super-heavy Walker ability does not apply while using this Stratagem).', 'matched play same stratagem per phase', 'start_phase', ('movement', 'charge',), 'friendly_unit', 'friendly_unit', ('TITANIC',), (), (), (), (), 'fe39e16f2710c8a0afa34c43bed1110cd5809a161443336a372d69c15f7b7940'),
    SourceStratagemActivationProfile('phase17s:stratagem:chaos-knights:traitoris-lance:000008517007', 'stratagem:chaos-knights:traitoris-lance:000008517007', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:chaos-knights:traitoris-lance:000008517007', 'chaos-knights', 'traitoris-lance', '000008517007', 'STORM OF DARKNESS', 1, 'strategic_ploy', "Your opponent's Shooting phase, just after an enemy unit has selected its targets.", "One Chaos Knights unit from your army that was selected as the target of one or more of the attacking unit's attacks.", 'Until the end of the phase, models in your unit have the Stealth ability, and each time an attack targets your unit, models in it have the Benefit of Cover against that attack.', 'matched play same stratagem per phase', 'after_unit_selected_as_target', ('shooting',), 'friendly_unit', 'selected_target_unit', (), (), (), (), (), 'c4bccee50c8ffacecdaeae6c106ee2bcbcd342e371cf09c36635784ae312e7d5'),
