    SourceStratagemActivationProfile('phase17s:stratagem:chaos-space-marines:cabal-of-chaos:000010152004', 'stratagem:chaos-space-marines:cabal-of-chaos:000010152004', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:chaos-space-marines:cabal-of-chaos:000010152004', 'chaos-space-marines', 'cabal-of-chaos', '000010152004', 'MUTATION\u2019S CURSE', 1, 'strategic_ploy', 'Your Shooting phase.', 'One Heretic Astartes Psyker unit from your army.', 'Select one visible enemy unit within 12" of your unit. Roll one D6: on a 1, that enemy unit suffers 1 mortal wound; on a 2-4, that enemy unit suffers D3 mortal wounds; on a 5-6, that enemy unit suffers 2D3 mortal wounds.', 'matched play same stratagem per phase', 'start_phase', ('shooting',), 'friendly_unit', 'friendly_unit', ('PSYKER',), (), (), (), (), 'ccd6504c156b20bb17ddd1e3f97c341d3fcc48376a0d2468a6ced278561c5025'),
