    SourceStratagemActivationProfile('phase17s:stratagem:chaos-space-marines:chaos-cult:000008982003', 'stratagem:chaos-space-marines:chaos-cult:000008982003', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:chaos-space-marines:chaos-cult:000008982003', 'chaos-space-marines', 'chaos-cult', '000008982003', 'SELFLESS DEMISE', 1, 'strategic_ploy', 'Fight phase, just after an enemy unit has selected its targets.', "One DAMNED unit from your army that was selected as the target of one or more of the attacking unit's attacks.", 'Until the attacking unit has resolved all of its attacks, each time a model in your unit is destroyed, roll one D6 on a 6, the attacking unit suffers 1 mortal wound after all of its attacks have been resolved.', 'matched play same stratagem per phase', 'after_unit_selected_as_target', ('fight',), 'friendly_unit', 'selected_target_unit', (), (), (), (), (), '1c15a3c84e0569eee246a2fe19e61cbb881b9110b8dd73d80ed3667c8e517441'),
    SourceStratagemActivationProfile('phase17s:stratagem:chaos-space-marines:chaos-cult:000008982004', 'stratagem:chaos-space-marines:chaos-cult:000008982004', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:chaos-space-marines:chaos-cult:000008982004', 'chaos-space-marines', 'chaos-cult', '000008982004', 'INFERNAL SACRIFICE', 1, 'battle_tactic', 'Fight phase.', 'One DAMNED unit from your army that has not been selected to fight this phase.', 'Your unit can make a Desperate Pact. If it does, your unit suffers D3 mortal wounds (in addition to any suffered for failing the resulting Leadership test), and until the end of the phase, add 1 to the Attacks characteristic of the melee weapons equipped by models in your unit, and if your unit did not fail the resulting Leadership test when making that Desperate Pact, until the end of the phase, improve the Strength characteristic of those weapons by 1 as well.', 'matched play same stratagem per phase', 'start_phase', ('fight',), 'friendly_unit', 'not_selected_to_fight_unit', (), (), (), (), (), 'ab9f8a8e06d387357fc550147f519c873ce028dea7c5e4998827c5aab4197cfc'),
    SourceStratagemActivationProfile('phase17s:stratagem:chaos-space-marines:chaos-cult:000008982005', 'stratagem:chaos-space-marines:chaos-cult:000008982005', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:chaos-space-marines:chaos-cult:000008982005', 'chaos-space-marines', 'chaos-cult', '000008982005', 'CRAZED FOCUS', 1, 'battle_tactic', 'Your Shooting phase.', 'One DAMNED unit from your army that has not been selected to shoot this phase.', 'Your unit can make a Desperate Pact. If it does, until the end of the phase, each time a model in your unit makes an attack, improve the Armour Penetration characteristic of that attack by 1, and if your unit did not fail the resulting Leadership test when making that Desperate Pact, improve the Strength characteristic of that attack by 1 as well.', 'matched play same stratagem per phase', 'start_phase', ('shooting',), 'friendly_unit', 'not_selected_to_shoot_unit', (), (), (), (), (), 'b72b9e85a3b1643287036ff68f9f963b20a7508bf6bae4ad966a861749687b16'),
    SourceStratagemActivationProfile('phase17s:stratagem:chaos-space-marines:chaos-cult:000008982006', 'stratagem:chaos-space-marines:chaos-cult:000008982006', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:chaos-space-marines:chaos-cult:000008982006', 'chaos-space-marines', 'chaos-cult', '000008982006', 'RECKLESS HASTE', 1, 'strategic_ploy', 'Your Charge phase', 'One DAMNED unit from your army.', 'Until the end of the turn, your unit is eligible to declare a charge in a turn in which it Advanced.', 'matched play same stratagem per phase', 'start_phase', ('charge',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), '3150ee3d32365c7653791669781e903b2ee86d0421c52e4ceabd9aec2ad8be91'),
    SourceStratagemActivationProfile('phase17s:stratagem:chaos-space-marines:chaos-cult:000008982007', 'stratagem:chaos-space-marines:chaos-cult:000008982007', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:chaos-space-marines:chaos-cult:000008982007', 'chaos-space-marines', 'chaos-cult', '000008982007', 'MORTAL THRALLS', 1, 'strategic_ploy', "Your opponent's Shooting phase, just after an enemy unit has selected ts targets.", 'One HERETIC ASTARTES unit from your army that was selected as the target of one or more of the attacking units attacks, and one friendly DAMNED unit within 3" of your unit and visible to both your unit and the attacking unit.', 'Until the end of the phase, while your DAMNED unit is on the battlefield, each time your opponent would make a Wound roll for an attack that targets your HERETIC ASTARTES unit, if your DAMNED unit is visible to the attacking model and is an eligible target for that attack, no roll is made; instead, your DAMNED unit suffers a number of mortal wounds equal to the Damage characteristic of that attack.', 'matched play same stratagem per phase', 'start_phase', ('shooting',), 'friendly_unit', 'selected_target_unit', (), (), (), (), (), '7bdcd486c62482d30cf94c6040269f6879bc44fd293a9ca63bffb86fe49e6fd0'),
    SourceStratagemActivationProfile('phase17s:stratagem:chaos-space-marines:creations-of-bile:000009774002', 'stratagem:chaos-space-marines:creations-of-bile:000009774002', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:chaos-space-marines:creations-of-bile:000009774002', 'chaos-space-marines', 'creations-of-bile', '000009774002', 'MONSTROUS VISAGES', 1, 'strategic_ploy', "Your opponent's Shooting phase or the Fight phase, just after an enemy unit has selected its targets.", "One Heretic Astartes Infantry unit from your army that was selected as the target of one or more of the attacking unit's attacks.", 'Until the end of the phase, each time an attack targets your unit, subtract 1 from the Hit roll.', 'matched play same stratagem per phase', 'after_unit_selected_as_target', ('shooting', 'fight',), 'friendly_unit', 'selected_target_unit', ('INFANTRY',), (), (), (), (), '9282392a3239e391ad1b8376a232aee3393a788d0634b5631b914dd1cef5417c'),
    SourceStratagemActivationProfile('phase17s:stratagem:chaos-space-marines:creations-of-bile:000009774003', 'stratagem:chaos-space-marines:creations-of-bile:000009774003', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:chaos-space-marines:creations-of-bile:000009774003', 'chaos-space-marines', 'creations-of-bile', '000009774003', 'MASTERS ARE WATCHING', 1, 'strategic_ploy', 'Fight phase, just after an enemy unit has selected its targets.', "One Heretic Astartes Infantry unit from your army that was selected as the target of one or more of the attacking unit's attacks.", 'Until the end of the phase, each time a model in your unit is destroyed, if that model has not fought this phase, roll one D6, subtracting 1 from the result if it is a Damned unit: on a 4+, do not remove it from play. That destroyed model can fight after the attacking unit has finished making its attacks, and is then removed from play.', 'matched play same stratagem per phase', 'after_unit_selected_as_target', ('fight',), 'friendly_unit', 'selected_target_unit', ('INFANTRY',), (), (), (), (), '910bf434522c8eb82fe8c25526252e2633bbde93926d8a439a903eaeb316fdf8'),
    SourceStratagemActivationProfile('phase17s:stratagem:chaos-space-marines:creations-of-bile:000009774004', 'stratagem:chaos-space-marines:creations-of-bile:000009774004', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:chaos-space-marines:creations-of-bile:000009774004', 'chaos-space-marines', 'creations-of-bile', '000009774004', 'SPECIMENS FOR THE SPIDER', 2, 'strategic_ploy', 'Fight phase.', 'One Heretic Astartes Infantry unit from your army that has not been selected to fight this phase.', 'Until the end of the phase, each time a model in your unit makes a melee attack that targets a CHARACTER unit, you can re-roll the Wound roll. After your unit has fought, if one or more enemy CHARACTER models were destroyed as a result of those attacks, select one enemy unit within 6" of your unit. That enemy unit must take a Battle-shock test. If the enemy WARLORD was destroyed as a result of those attacks, each enemy unit within 6" of your unit must take a Battle-shock test instead.', 'matched play same stratagem per phase', 'start_phase', ('fight',), 'friendly_unit', 'not_selected_to_fight_unit', ('INFANTRY',), (), (), (), (), '1dc828643f72bfaae374276114af01244c2e9e1f5f89e556cc5d47cfc9cb0f77'),
