    SourceStratagemActivationProfile('phase17s:stratagem:drukhari:covenite-coterie:000010585002', 'stratagem:drukhari:covenite-coterie:000010585002', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:drukhari:covenite-coterie:000010585002', 'drukhari', 'covenite-coterie', '000010585002', 'POSTMORTALITY', 1, 'epic_deed', 'Any phase.', 'One Haemonculus model from your army that was just destroyed. You can use this Stratagem on that model even though it was just destroyed.', 'Spend 1-3 Pain tokens. At the end of the phase, set the destroyed model back up on the battlefield, as close as possible to where it was destroyed and not within Engagement Range of any enemy units, with a number of wounds remaining equal to the number of Pain tokens you just spent. RESTRICTIONS: You cannot use this Stratagem if you have 0 Pain tokens, and you cannot target the same HAEMONCULUS model with this Stratagem more than once per battle.', 'matched play same stratagem per phase', 'start_phase', ('any',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), '305d763c7fff4446763a986b5fe55278fd8fac94e949e3ae050c10faa7de890e'),
