    SourceStratagemActivationProfile('phase17s:stratagem:drukhari:covenite-coterie:000010585004', 'stratagem:drukhari:covenite-coterie:000010585004', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:drukhari:covenite-coterie:000010585004', 'drukhari', 'covenite-coterie', '000010585004', 'POISONER\u2019S ART', 1, 'epic_deed', 'Fight phase, just after a Haemonculus Covens unit from your army has fought.', 'That HAEMONCULUS COVENS unit.', "Select one enemy unit (excluding VEHICLES) hit by one or more of your unit's attacks this phase. Until the end of the battle, that enemy unit is poisoned. At the start of each Command phase, roll one D6 for each poisoned unit on the battlefield: on a 4+, that unit suffers D3 mortal wounds.", 'matched play same stratagem per phase', 'start_phase', ('fight',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), 'c2c5fb387f1e5d99a393ef36585842a2b95ae185cf45088f0ac8e36ae4cd230f'),
    SourceStratagemActivationProfile('phase17s:stratagem:drukhari:covenite-coterie:000010585005', 'stratagem:drukhari:covenite-coterie:000010585005', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:drukhari:covenite-coterie:000010585005', 'drukhari', 'covenite-coterie', '000010585005', 'DISTILLERS OF FEAR', 2, 'strategic_ploy', 'Fight phase.', 'One Haemonculus Covens unit from your army that has not been selected to fight this phase.', 'Until the end of the phase, each time a model in your unit makes an attack that targets an enemy unit that is Battle-shocked, that attack has the [DEVASTATING WOUNDS] ability.', 'matched play same stratagem per phase', 'start_phase', ('fight',), 'friendly_unit', 'not_selected_to_fight_unit', (), (), (), (), (), '77fcdb22941f2adb08d8a588a05744ce811f9d449c5438923548745c4b7b9df9'),
    SourceStratagemActivationProfile('phase17s:stratagem:drukhari:covenite-coterie:000010585006', 'stratagem:drukhari:covenite-coterie:000010585006', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:drukhari:covenite-coterie:000010585006', 'drukhari', 'covenite-coterie', '000010585006', 'CONNOISSEURS OF PAIN', 1, 'battle_tactic', "Your opponent's Shooting phase or the Fight phase, just after an enemy unit has selected its targets.", "One Drukhari unit from your army that was selected as the target of one or more of the attacking unit's attacks.", 'Spend 1 Pain token. Until the attacking unit has finished making its attacks, each time an attack targets your unit, worsen the Armour Penetration characteristic of that attack by 1. At the end of the phase, if your unit is still on the battlefield and it is a Haemonculus Covens unit, you gain 1 Pain token.', 'matched play same stratagem per phase', 'after_unit_selected_as_target', ('shooting', 'fight',), 'friendly_unit', 'selected_target_unit', (), (), (), (), (), '4394b3820e71a361b22129a687edfa32e7a0be6b8dc291fed54e2e2631cad623'),
    SourceStratagemActivationProfile('phase17s:stratagem:drukhari:covenite-coterie:000010585007', 'stratagem:drukhari:covenite-coterie:000010585007', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:drukhari:covenite-coterie:000010585007', 'drukhari', 'covenite-coterie', '000010585007', 'ENFOLDING NIGHTMARE', 1, 'strategic_ploy', "Your opponent's Shooting phase, just after an enemy unit has shot.", "One Haemonculus Covens unit from your army that was selected as the target of one or more of the attacking unit's attacks.", 'Roll one D6: your unit can be moved a number of inches up to the result, but it must end that move as close as possible to the closest enemy unit (excluding AIRCRAFT). When doing so, those models can be moved within Engagement Range of that enemy unit.', 'matched play same stratagem per phase', 'just_after_enemy_unit_has_shot', ('shooting',), 'friendly_unit', 'selected_target_unit', (), (), (), (), (), '50947a59a3e42547affb23730ce48d27fcf746c80eba1f7b3cd82d4975f03762'),
    SourceStratagemActivationProfile('phase17s:stratagem:drukhari:kabalite-cartel:000010589002', 'stratagem:drukhari:kabalite-cartel:000010589002', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:drukhari:kabalite-cartel:000010589002', 'drukhari', 'kabalite-cartel', '000010589002', 'DOUBLE-CROSS', 1, 'strategic_ploy', 'Fight phase, just after an enemy unit has selected its targets.', "One Kabal or Blades for Hire unit from your army that was selected as the target of one or more of the attacking unit's attacks, and one friendly Drukhari unit (excluding Vehicles).", 'Until the end of the phase, each time you would allocate an attack to a model in your KABAL or BLADES FOR HIRE unit, if your DRUKHARI unit is within Engagement Range of the attacking model, no saving throw is made for that attack; instead, your DRUKHARI unit suffers a number of mortal wounds equal to the Damage characteristic of that attack.', 'matched play same stratagem per phase', 'after_unit_selected_as_target', ('fight',), 'friendly_unit', 'selected_target_unit', (), (), (), ('VEHICLES',), (), 'a14ad12cd22a3e78b2ea5cf225f2f1cd05c18e4b5bb6e3acbddb2a01c31fce3e'),
    SourceStratagemActivationProfile('phase17s:stratagem:drukhari:kabalite-cartel:000010589003', 'stratagem:drukhari:kabalite-cartel:000010589003', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:drukhari:kabalite-cartel:000010589003', 'drukhari', 'kabalite-cartel', '000010589003', 'TAKEN ALIVE', 1, 'battle_tactic', 'Fight phase.', 'One Drukhari unit from your army that has not been selected to fight this phase.', "Until the end of the phase, each time a model in your unit makes an attack, add 1 to the Hit roll. If your Contract unit is destroyed as a result of those attacks, every unit in your opponent's army must take a Battle-shock test. You cannot gain more than 3 Pain tokens as a result of failed Battle-shock tests caused by this Stratagem.", 'matched play same stratagem per phase', 'start_phase', ('fight',), 'friendly_unit', 'not_selected_to_fight_unit', (), (), (), (), (), 'd7e95b2463d192e837849dbff9ea52bc0cf8062c29ac167233ce913e3448d9ab'),
    SourceStratagemActivationProfile('phase17s:stratagem:drukhari:kabalite-cartel:000010589004', 'stratagem:drukhari:kabalite-cartel:000010589004', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:drukhari:kabalite-cartel:000010589004', 'drukhari', 'kabalite-cartel', '000010589004', 'TAILORED TOXINS', 1, 'epic_deed', 'Your Shooting phase or the Fight phase.', 'One Kabal or Blades for Hire unit from your army that has not been selected to shoot or fight this phase.', 'Until the end of the phase, each time a model in your unit makes an attack that targets your Contract unit, an unmodified Hit roll of 5+ scores a Critical Hit.', 'matched play same stratagem per phase', 'start_phase', ('shooting', 'fight',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), '033845aa4cffac5f3b402a22508288c8126a6def79b87f41c297393600f6feb5'),
