    SourceStratagemActivationProfile('phase17s:stratagem:drukhari:reapers-wager:000009782005', 'stratagem:drukhari:reapers-wager:000009782005', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:drukhari:reapers-wager:000009782005', 'drukhari', 'reapers-wager', '000009782005', 'SHORTEN THE ODDS', 1, 'strategic_ploy', 'Your Movement phase, just after a Drukhari or Harlequins unit from your army has Advanced.', 'That unit.', 'Until the end of the turn, your unit is eligible to shoot and declare a charge in a turn in which it Advanced.', 'matched play same stratagem per phase', 'start_phase', ('movement',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), '19ff6b6451fefea57e07260b68e81322d4c5141e2e39d2f0f462f9a436423af5'),
