    SourceStratagemActivationProfile('phase17s:stratagem:imperial-agents:veiled-blade-elimination-force:000009758002', 'stratagem:imperial-agents:veiled-blade-elimination-force:000009758002', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:imperial-agents:veiled-blade-elimination-force:000009758002', 'imperial-agents', 'veiled-blade-elimination-force', '000009758002', 'PRIME TARGET', 1, 'battle_tactic', 'Your Shooting phase or the Fight phase.', 'One Agents of the Imperium unit from your army that has not been selected to shoot or fight this phase.', 'Until the end of the phase, each time a model in your unit makes an attack that targets a CHARACTER unit, re-roll a Wound roll of 1. If that attack is made by an Officio Assassinorum model and it targets the enemy WARLORD, you can re-roll the Wound roll instead.', 'matched play same stratagem per phase', 'start_phase', ('shooting', 'fight',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), '2e1d36a2916e4a500ce94a51df83a04b3fc63ce0d4cc82aa12c7a6054d37ce48'),
