    SourceStratagemActivationProfile('phase17s:stratagem:imperial-agents:veiled-blade-elimination-force:000009758004', 'stratagem:imperial-agents:veiled-blade-elimination-force:000009758004', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:imperial-agents:veiled-blade-elimination-force:000009758004', 'imperial-agents', 'veiled-blade-elimination-force', '000009758004', 'WILL\u2011SAPPING SALVO', 1, 'strategic_ploy', 'Your Shooting phase.', 'One Agents of the Imperium Infantry unit from your army that has not been selected to shoot this phase.', 'Until the end of the phase, ranged weapons equipped by models in your unit have the [SUSTAINED HITS 1] ability. In addition, if it is a Culexus Assassin unit, until the end of the phase, change the Damage characteristic of ranged weapons equipped by models in your unit to 3.', 'matched play same stratagem per phase', 'start_phase', ('shooting',), 'friendly_unit', 'not_selected_to_shoot_unit', ('INFANTRY',), (), (), (), (), 'c9c4bb478c346df8db0f44caa4f04014d01136240e63a955ef0061fb4f27c2d9'),
    SourceStratagemActivationProfile('phase17s:stratagem:imperial-agents:veiled-blade-elimination-force:000009758005', 'stratagem:imperial-agents:veiled-blade-elimination-force:000009758005', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:imperial-agents:veiled-blade-elimination-force:000009758005', 'imperial-agents', 'veiled-blade-elimination-force', '000009758005', 'ORBITAL OVERSIGHT', 1, 'strategic_ploy', "Your opponent's Shooting phase, just after an enemy unit has selected its targets.", "One Agents of the Imperium Infantry unit from your army that was selected as the target of one or more of the attacking unit's attacks.", 'Until the end of the phase, your unit can only be selected as the target of a ranged attack if the attacking model is within 18", or, if your unit has the Lone Operative ability, if the attacking model is within 6".', 'matched play same stratagem per phase', 'after_unit_selected_as_target', ('shooting',), 'friendly_unit', 'selected_target_unit', ('INFANTRY',), (), (), (), (), 'a0021c813aed55993b1e047e228a31ebcb85001aa3b962cfc0bf31da266fccdf'),
    SourceStratagemActivationProfile('phase17s:stratagem:imperial-agents:veiled-blade-elimination-force:000009758006', 'stratagem:imperial-agents:veiled-blade-elimination-force:000009758006', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:imperial-agents:veiled-blade-elimination-force:000009758006', 'imperial-agents', 'veiled-blade-elimination-force', '000009758006', 'BLIND GRENADES', 1, 'strategic_ploy', "Your opponent's Charge phase, just after an enemy unit has declared a charge.", 'One Agents of the Imperium Grenades or Vindicare Assassin unit from your army that was selected as one of the targets of that charge and is not within Engagement Range of one or more enemy units.', 'Until the end of the phase, subtract 1 from Charge rolls made for that enemy unit, or, if your unit is a VINDICARE ASSASSIN, subtract 2 from Charge rolls made for that enemy unit instead.', 'matched play same stratagem per phase', 'start_phase', ('charge',), 'friendly_unit', 'friendly_unit', ('GRENADES',), (), (), (), (), '2957e739e279713514bb95fc3d2a72237e3e0e2e5371b5c393e8125d4b3077b6'),
    SourceStratagemActivationProfile('phase17s:stratagem:imperial-agents:veiled-blade-elimination-force:000009758007', 'stratagem:imperial-agents:veiled-blade-elimination-force:000009758007', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:imperial-agents:veiled-blade-elimination-force:000009758007', 'imperial-agents', 'veiled-blade-elimination-force', '000009758007', 'ENSNARING TRAP', 1, 'strategic_ploy', "End of your opponent's Charge phase.", 'One Agents of the Imperium Infantry unit from your army that is within 6" of one or more enemy units and would be eligible to declare a charge against one or more of those enemy units.', 'Your unit can declare a charge. When doing so, you must select one or more of those enemy units as the targets of that charge, and your unit does not receive a Charge bonus this turn. In addition, if it is a Callidus Assassin unit and it makes a Charge move as a result of this Stratagem, until the end of the turn, each time a model in your unit makes a melee attack, add 1 to the Wound roll.', 'matched play same stratagem per phase', 'end_phase', ('charge',), 'friendly_unit', 'friendly_unit', ('INFANTRY',), (), (), (), (), '3a8e7ecccbd1e06e0e0fd47f5645641c8d6826b9ca0b00b1d1cb2d9fba7b3f48'),
    SourceStratagemActivationProfile('phase17s:stratagem:imperial-knights:freeblade-company:000010756002', 'stratagem:imperial-knights:freeblade-company:000010756002', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:imperial-knights:freeblade-company:000010756002', 'imperial-knights', 'freeblade-company', '000010756002', 'NOBLE SACRIFICE', 1, 'epic_deed', 'Any phase.', 'One Imperial Knights unit from your army that was just destroyed. You can target that unit with this Stratagem even though it was just destroyed.', "Your unit's Deadly Demise ability inflicts mortal wounds on a D6 roll of 4+, adding 1 to the result if it is an Armiger unit, instead of only a 6.", 'matched play same stratagem per phase', 'start_phase', ('any',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), '43d78721e3a0fef4f5421407717994ba35ed0fef654f8c8c42aeae5fa5df04e8'),
    SourceStratagemActivationProfile('phase17s:stratagem:imperial-knights:freeblade-company:000010756003', 'stratagem:imperial-knights:freeblade-company:000010756003', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:imperial-knights:freeblade-company:000010756003', 'imperial-knights', 'freeblade-company', '000010756003', 'STRENGTH FROM EXILE', 1, 'battle_tactic', 'Your Shooting phase or the Fight phase.', 'One Imperial Knights unit from your army that has not been selected to shoot or fight this phase.', 'Until the end of the phase, each time a model in your unit makes an attack, if there are no other friendly units within 9" of your unit, re-roll a Hit roll of 1 and re-roll a Wound roll of 1.', 'matched play same stratagem per phase', 'start_phase', ('shooting', 'fight',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), 'c5c506d88cdac7ce66ec5186916b9c30bdaf8e5d231dc2f9ccc8461cea2c9979'),
    SourceStratagemActivationProfile('phase17s:stratagem:imperial-knights:freeblade-company:000010756004', 'stratagem:imperial-knights:freeblade-company:000010756004', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:imperial-knights:freeblade-company:000010756004', 'imperial-knights', 'freeblade-company', '000010756004', 'FULL TILT', 1, 'wargear', 'Your Movement phase.', 'One Imperial Knights unit from your army.', 'Until the end of the phase, if your unit Advances, do not make an Advance roll for it. Instead, until the end of the phase, add 6" to the Move characteristic of models in your unit, or 9" instead if your unit is an Armiger or Destrier unit.', 'matched play same stratagem per phase', 'start_phase', ('movement',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), '9874b3f80f64ae84157bd1f302be10efbe0274e94f087fd06d681f4b77c50379'),
    SourceStratagemActivationProfile('phase17s:stratagem:imperial-knights:freeblade-company:000010756005', 'stratagem:imperial-knights:freeblade-company:000010756005', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:imperial-knights:freeblade-company:000010756005', 'imperial-knights', 'freeblade-company', '000010756005', 'POINT\u2011BLANK BARRAGE', 1, 'strategic_ploy', 'Your Shooting phase.', 'One Imperial Knights unit from your army that has not been selected to shoot this phase.', 'Until the end of the phase, when making ranged attacks with Blast weapons, models in your unit can target enemy units within Engagement Range of your unit (provided no other friendly units are also within Engagement Range of that enemy unit). In addition, until the end of the phase, your unit does not suffer the penalty to its Hit rolls for being within Engagement Range of one or more enemy units, but each time a model in your unit makes an attack with a Blast weapon that targets a unit within Engagement Range of your unit, on an unmodified Hit roll of 1, your unit suffers 1 mortal wound after all of its attacks have been resolved.', 'matched play same stratagem per phase', 'start_phase', ('shooting',), 'friendly_unit', 'not_selected_to_shoot_unit', (), (), (), (), (), '89ecd7b3dd5444496c8e7d8ceee7671fa49f4ee4656ff7b58b17d742e01b6c89'),
