    SourceStratagemActivationProfile('phase17s:stratagem:imperial-knights:freeblade-company:000010756007', 'stratagem:imperial-knights:freeblade-company:000010756007', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:imperial-knights:freeblade-company:000010756007', 'imperial-knights', 'freeblade-company', '000010756007', 'FLANKING MANOEUVRES', 1, 'strategic_ploy', "End of your opponent's Fight phase.", 'One Armiger unit from your army that is within 9" of one or more battlefield edges and not within Engagement Range of one or more enemy units.', 'Remove your unit from the battlefield and place it into Strategic Reserves.', 'matched play same stratagem per phase', 'end_phase', ('fight',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), 'dbb8066d5a268bb9bde0c7ee2cd78dbedcc7d754be8a4b59cecccfef048604d1'),
