    SourceStratagemActivationProfile('phase17s:stratagem:imperial-knights:gate-warden-lance:000010498004', 'stratagem:imperial-knights:gate-warden-lance:000010498004', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:imperial-knights:gate-warden-lance:000010498004', 'imperial-knights', 'gate-warden-lance', '000010498004', 'STEADFAST SUPERIORITY', 1, 'battle_tactic', 'Fight phase.', 'One Imperial Knights unit from your army that is within Engagement Range of one or more enemy units, that is on your defensive line and that has not already been selected to fight this phase.', 'Until the end of the phase, each time a model in your unit makes an attack, you can re-roll the Hit roll.', 'matched play same stratagem per phase', 'start_phase', ('fight',), 'friendly_unit', 'not_selected_to_fight_unit', (), (), (), (), (), '95da9dca3a26d7f45416776e2cc45d258fa289a89218c3819498b5ac05fa9c48'),
