    SourceStratagemActivationProfile('phase17s:stratagem:imperial-knights:questor-forgepact:000009762002', 'stratagem:imperial-knights:questor-forgepact:000009762002', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:imperial-knights:questor-forgepact:000009762002', 'imperial-knights', 'questor-forgepact', '000009762002', 'OMNISSIAH\u2019S GRACE', 1, 'strategic_ploy', 'Any phase, just after a mortal wound is allocated to an Imperial Knights or Adeptus Mechanicus unit from your army.', 'That IMPERIAL KNIGHTS or ADEPTUS MECHANICUS unit.', 'Until the end of the phase, models in your unit have the Feel No Pain 5+ ability against mortal wounds.', 'matched play same stratagem per phase', 'start_phase', ('any',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), 'bd30493ef02bbbf065c27ca0f0864d603a5abebf8abe48ec341b0a76f4d015ee'),
    SourceStratagemActivationProfile('phase17s:stratagem:imperial-knights:questor-forgepact:000009762003', 'stratagem:imperial-knights:questor-forgepact:000009762003', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:imperial-knights:questor-forgepact:000009762003', 'imperial-knights', 'questor-forgepact', '000009762003', 'VENGEANCE OF THE MACHINE CULT', 1, 'strategic_ploy', 'Any phase.', 'One Imperial Knights unit from your army that was just destroyed. You can use this Stratagem on that unit even though it was just destroyed.', 'Until the end of the battle, the enemy unit that destroyed your unit is Marked. Each time an Adeptus Mechanicus model from your army makes an attack that targets a Marked unit, that attack has the [LETHAL HITS] ability.', 'matched play same stratagem per phase', 'start_phase', ('any',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), 'e5f722a16a0994b906f44865fd77d7f8dcf5cf31c4f369b2fc0697cfa379c828'),
    SourceStratagemActivationProfile('phase17s:stratagem:imperial-knights:questor-forgepact:000009762004', 'stratagem:imperial-knights:questor-forgepact:000009762004', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:imperial-knights:questor-forgepact:000009762004', 'imperial-knights', 'questor-forgepact', '000009762004', 'BONDED IMPERATIVE', 1, 'epic_deed', 'Your Command phase, just before an Imperial Knights Character unit from your army uses a Bondsman ability.', 'That IMPERIAL KNIGHTS CHARACTER unit.', 'When selecting targets for that use of that Bondsman ability, you can select one friendly Adeptus Mechanicus unit within 12" of your unit in addition, or instead of selecting one Armiger model. Until the start of your next Command phase, every model in that ADEPTUS MECHANICUS unit is affected by that Bondsman ability. RESTRICTIONS: You cannot target a Knight Preceptor with this Stratagem.', 'matched play same stratagem per phase', 'start_phase', ('command',), 'friendly_unit', 'friendly_unit', ('CHARACTER',), (), (), (), (), '184bda9a78fff48d09ab02105b490a685eed80b5c91b085bc9596e4470ee2226'),
    SourceStratagemActivationProfile('phase17s:stratagem:imperial-knights:questor-forgepact:000009762005', 'stratagem:imperial-knights:questor-forgepact:000009762005', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:imperial-knights:questor-forgepact:000009762005', 'imperial-knights', 'questor-forgepact', '000009762005', 'MACHINE FOCUS', 1, 'strategic_ploy', 'Your Command phase.', 'One Imperial Knights unit from your army.', 'Until the start of your next turn, your unit can ignore any or all modifiers to the following: the Weapon Skill or Ballistic Skill characteristics of weapons equipped by its models; any Hit roll or Wound roll made for it.', 'matched play same stratagem per phase', 'start_phase', ('command',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), 'a39aba10770ef66e44c3773a25ce7e9f1a4cf90800ceecaa86158a278720cfae'),
    SourceStratagemActivationProfile('phase17s:stratagem:imperial-knights:questor-forgepact:000009762006', 'stratagem:imperial-knights:questor-forgepact:000009762006', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:imperial-knights:questor-forgepact:000009762006', 'imperial-knights', 'questor-forgepact', '000009762006', 'AGGRESSION BEGETS AGGRESSION', 1, 'strategic_ploy', 'Your Shooting phase.', 'One Imperial Knights unit from your army or one Imperial Knights Character unit from your army and one friendly Adeptus Mechanicus unit that is within 6" of that unit.', 'Until the end of the phase, ranged weapons equipped by models in your units have the [ASSAULT] ability.', 'matched play same stratagem per phase', 'start_phase', ('shooting',), 'friendly_unit', 'friendly_unit', ('CHARACTER',), (), (), (), (), '5372f07984d6696288d46f48f31c1674ace00b71d8c9e7d570dca493b6e3acda'),
