    SourceStratagemActivationProfile('phase17s:stratagem:orks:blitz-brigade:000010800007', 'stratagem:orks:blitz-brigade:000010800007', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:orks:blitz-brigade:000010800007', 'orks', 'blitz-brigade', '000010800007', 'YOOZ IN TROUBLE NOW', 1, 'strategic_ploy', "Your opponent's Shooting phase, just after an enemy unit has shot.", "One Battlewagon, Hunta Rig or Kill Rig model from your army that was hit by one or more of the attacking unit's attacks.", 'One Orks Infantry unit embarked within your model can disembark and make a Surge move. To do so, roll one D6: models in that unit move a number of inches up to this result, but that unit must end that move as close as possible to the closest enemy unit (excluding AIRCRAFT). When doing so, those models can be moved within Engagement Range of that enemy unit.', 'matched play same stratagem per phase', 'just_after_enemy_unit_has_shot', ('shooting',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), '4d1e83e12d7b62352949f92e11bd795a47e16fde3050dbfbfa4ae0cc9cde8031'),
    SourceStratagemActivationProfile('phase17s:stratagem:orks:bully-boyz:000008886002', 'stratagem:orks:bully-boyz:000008886002', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:orks:bully-boyz:000008886002', 'orks', 'bully-boyz', '000008886002', 'ARMED TO DATEEF', 1, 'battle_tactic', 'Your Shooting phase or the Fight phase.', 'One Nobz or Meganobz unit from your army that has not been selected to shoot or fight this phase.', 'Until the end of the phase, each time a model in your unit makes an attack, re-roll a Hit roll of 1. If a Waaagh! is active for your unit, you can re-roll the Hit roll instead.', 'matched play same stratagem per phase', 'start_phase', ('shooting', 'fight',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), '296484eea18106abd91fb339e7eac22f285fba5e046f579dd2a2af86e65a3281'),
    SourceStratagemActivationProfile('phase17s:stratagem:orks:bully-boyz:000008886003', 'stratagem:orks:bully-boyz:000008886003', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:orks:bully-boyz:000008886003', 'orks', 'bully-boyz', '000008886003', 'TOO ARROGANT TO DIE', 1, 'strategic_ploy', "Your opponent's Shooting phase or the Fight phase, just after an enemy unit has selected its targets.", "One Nobz or Meganobz unit from your army that was selected as the target of one or more of the attacking unit's attacks.", 'Until the end of the phase, each time a model in your unit is destroyed, if that model has not shot or fought this phase, roll one D6, adding 2 to the result if a Waaagh! is active for your unit. On a 5+, do not remove the destroyed model from play; it can shoot or fight after the attacking unit has finished making its attacks, and is then removed from play.', 'matched play same stratagem per phase', 'after_unit_selected_as_target', ('shooting', 'fight',), 'friendly_unit', 'selected_target_unit', (), (), (), (), (), 'dabae0392585f748c6d7ee60cbc7bc64cbe44f310302c2af8bc985eaaec26004'),
    SourceStratagemActivationProfile('phase17s:stratagem:orks:bully-boyz:000008886004', 'stratagem:orks:bully-boyz:000008886004', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:orks:bully-boyz:000008886004', 'orks', 'bully-boyz', '000008886004', 'ALWAYS LOOKIN\u2019 FER A FIGHT', 1, 'strategic_ploy', 'Fight phase, just after an enemy unit is destroyed.', 'One Nobz or Meganobz unit from your army that destroyed that enemy unit.', 'Until the end of the phase, each time your unit makes a Consolidation move, it can move up to D3+3" instead of up to 3". If a Waaagh! is active for your unit, it can move up to 6" instead.', 'matched play same stratagem per phase', 'start_phase', ('fight',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), 'ae9a13f4c2984295b906fceca8c0b632e61db75e2b3534fd2fff41931c8055fa'),
    SourceStratagemActivationProfile('phase17s:stratagem:orks:bully-boyz:000008886005', 'stratagem:orks:bully-boyz:000008886005', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:orks:bully-boyz:000008886005', 'orks', 'bully-boyz', '000008886005', 'CRUSHING IMPACT', 1, 'epic_deed', 'Your Charge phase, just after a Nobz or Meganobz unit from your army ends a Charge move.', 'That NOBZ or MEGANOBZ unit.', 'Select one enemy unit within Engagement Range of your unit, then roll one D6 for each model in your unit that is within Engagement Range of that enemy unit: for each 5+, that enemy unit suffers 1 mortal wound (to a maximum of 6 mortal wounds). If a Waaagh! is active for your unit, that enemy unit suffers 1 mortal wound for each 4+ instead.', 'matched play same stratagem per phase', 'after_unit_ends_charge_move', ('charge',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), '67e42346997f262fe61d5cb34aaa578e0c191fe71a48e075d5ade35583cb3c97'),
    SourceStratagemActivationProfile('phase17s:stratagem:orks:bully-boyz:000008886006', 'stratagem:orks:bully-boyz:000008886006', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:orks:bully-boyz:000008886006', 'orks', 'bully-boyz', '000008886006', 'CUT\u2019EM DOWN', 1, 'battle_tactic', "Your opponent's Movement phase, just after an enemy unit is selected to Fall Back.", 'One Nobz or Meganobz unit from your army within Engagement Range of that enemy unit.', 'When that enemy unit Falls Back, all models in that enemy unit must take a Desperate Escape test. When doing so, if a Waaagh! is active for your unit, subtract 1 from each of those tests.', 'matched play same stratagem per phase', 'just_after_enemy_unit_selected_to_fall_back', ('movement',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), '55faa5ef9e8cca86ef6bb44323cd37bc8812ef1151995c98fac6ce5c944a72e9'),
