    SourceStratagemActivationProfile('phase17s:stratagem:orks:da-big-hunt:000008869002', 'stratagem:orks:da-big-hunt:000008869002', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:orks:da-big-hunt:000008869002', 'orks', 'da-big-hunt', '000008869002', 'DRAG IT DOWN', 1, 'battle_tactic', 'Fight phase.', 'One Beast Snagga unit from your army that has not been selected to fight this phase.', 'Until the end of the phase, melee weapons equipped by models in your unit have the [SUSTAINED HITS 1] ability. In addition, each time a model in your unit makes a melee attack that targets your Prey, a Critical Hit is scored on an unmodified Hit roll of 5+, instead of only a 6.', 'matched play same stratagem per phase', 'start_phase', ('fight',), 'friendly_unit', 'not_selected_to_fight_unit', ('BEAST',), (), (), (), (), '6c30e4bdb8ab959fcb2e30f58482aad1c0203f33ee9acbb3fc47f3104a3aeb84'),
    SourceStratagemActivationProfile('phase17s:stratagem:orks:da-big-hunt:000008869003', 'stratagem:orks:da-big-hunt:000008869003', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:orks:da-big-hunt:000008869003', 'orks', 'da-big-hunt', '000008869003', 'UNSTOPPABLE MOMENTUM', 1, 'strategic_ploy', 'Your Charge phase, just after a Beast Snagga Mounted unit from your army ends a Charge move.', 'That Beast Snagga unit.', 'Select one enemy unit within Engagement Range of your unit and roll one D6 for each model in your unit: for each 4+, that enemy unit suffers 1 mortal wound (to a maximum of 6 mortal wounds). If that enemy unit is your Prey, roll three additional D6.', 'matched play same stratagem per phase', 'after_unit_ends_charge_move', ('charge',), 'friendly_unit', 'friendly_unit', ('BEAST',), (), (), (), (), 'e97ada752205ea142cd5cdfa2b16c36bb7b513b3bf1a2e68edfc4cdc45bcedf4'),
    SourceStratagemActivationProfile('phase17s:stratagem:orks:da-big-hunt:000008869004', 'stratagem:orks:da-big-hunt:000008869004', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:orks:da-big-hunt:000008869004', 'orks', 'da-big-hunt', '000008869004', 'DAT ONE\u2019S EVEN BIGGA!', 1, 'strategic_ploy', 'Your Charge phase.', 'One Beast Snagga unit from your army.', 'Until the end of the phase, your unit is eligible to charge in a turn in which it Advanced or Fell Back. In addition, you can re-roll Charge rolls made for your unit, provided one of the targets of that charge is your Prey.', 'matched play same stratagem per phase', 'start_phase', ('charge',), 'friendly_unit', 'friendly_unit', ('BEAST',), (), (), (), (), '2dd983e558f59131a17ae1fa36c9275384f932bb3be1f18347ee13fafa4741f0'),
