    SourceStratagemActivationProfile('phase17s:stratagem:orks:dread-mob:000008878003', 'stratagem:orks:dread-mob:000008878003', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:orks:dread-mob:000008878003', 'orks', 'dread-mob', '000008878003', 'SUPERFUELLED BOILER', 1, 'strategic_ploy', 'Your Movement phase, just after an Orks Walker unit from your army has been selected to Advance.', 'That Orks Walker unit.', 'Until the end of the turn, you can re-roll Advance rolls made for your unit and ranged weapons equipped by models in your unit have the [ASSAULT] ability.', 'matched play same stratagem per phase', 'start_phase', ('movement',), 'friendly_unit', 'friendly_unit', ('WALKER',), (), (), (), (), '7bb4e7abec3a5682c7f5b83294fbe7fd6f388f94fe38ca8d42928e5ccbf91356'),
