    SourceStratagemActivationProfile('phase17s:stratagem:space-marines:armoured-speartip:000010780005', 'stratagem:space-marines:armoured-speartip:000010780005', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:space-marines:armoured-speartip:000010780005', 'space-marines', 'armoured-speartip', '000010780005', 'CERAMITE SLEDGEHAMMER', 1, 'strategic_ploy', 'Your Movement phase.', 'One Adeptus Astartes Transport unit from your army that has not been selected to move this phase.', 'Until the end of the phase, each time your unit makes a Normal or Advance move, it can move horizontally through terrain features. In addition, if your unit is a Heavy Transport, when making this move, your unit can move through enemy models (excluding MONSTERS and VEHICLES) and can move within Engagement Range of such models, but cannot end that move within Engagement Range of them, and any Desperate Escape test is automatically passed.', 'matched play same stratagem per phase', 'start_phase', ('movement',), 'friendly_unit', 'selected_to_move_unit', ('TRANSPORT',), (), (), (), (), '72fb466e0113fee70f28e8436c0c1b08a099c879a5d7591f13cd0e325d8bffe9'),
    SourceStratagemActivationProfile('phase17s:stratagem:space-marines:armoured-speartip:000010780006', 'stratagem:space-marines:armoured-speartip:000010780006', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:space-marines:armoured-speartip:000010780006', 'space-marines', 'armoured-speartip', '000010780006', 'ADVANCED DEPLOYMENT', 1, 'strategic_ploy', 'Your Movement phase.', 'One Adeptus Astartes Transport unit from your army that has not been selected to move this phase.', 'Until the end of the phase, units can disembark from your TRANSPORT after it has Advanced. Units that do so count as having made a Normal move this phase, and cannot declare a charge in the same turn (unless your TRANSPORT has the Assault Ramp ability), but can otherwise act normally.', 'matched play same stratagem per phase', 'start_phase', ('movement',), 'friendly_unit', 'selected_to_move_unit', ('TRANSPORT',), (), (), (), (), '6639c66d5cd64c206de952519aa160ae6e21e3f910d40e1f43d0ae2c9f1956d5'),
    SourceStratagemActivationProfile('phase17s:stratagem:space-marines:armoured-speartip:000010780007', 'stratagem:space-marines:armoured-speartip:000010780007', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:space-marines:armoured-speartip:000010780007', 'space-marines', 'armoured-speartip', '000010780007', 'PURGATION DOCTRINE', 1, 'battle_tactic', 'Your Shooting phase.', 'One ADEPTUS ASTARTES unit from your army that has not been selected to shoot this phase.', 'Until the end of the phase, each time a model in your unit makes an attack, add 1 to the Hit roll (if your unit disembarked from a Heavy Transport this turn, add 1 to the Wound roll as well).', 'matched play same stratagem per phase', 'start_phase', ('shooting',), 'friendly_unit', 'not_selected_to_shoot_unit', (), (), (), (), (), '698b1355fe8319d599159b50ed9ebae44f77e0262f8bfaf8c6e3540034fc46ad'),
