    SourceStratagemActivationProfile('phase17s:stratagem:space-marines:stormlance-task-force:000008487005', 'stratagem:space-marines:stormlance-task-force:000008487005', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:space-marines:stormlance-task-force:000008487005', 'space-marines', 'stormlance-task-force', '000008487005', 'SHOCK ASSAULT', 1, 'battle_tactic', 'Your Charge phase.', 'One ADEPTUS ASTARTES MOUNTED unit from your army that has not declared a charge this phase.', 'Until the end of the turn, you can re-roll Charge rolls made for your unit and melee weapons equipped by models in that unit have the [LANCE] ability.', 'matched play same stratagem per phase', 'start_phase', ('charge',), 'friendly_unit', 'friendly_unit', ('MOUNTED',), (), (), (), (), 'fcd2f99ee9a9e0c1d3043d69dd93f3dd1078353fe4ba5b05fb430b28d009bb51'),
    SourceStratagemActivationProfile('phase17s:stratagem:space-marines:stormlance-task-force:000008487006', 'stratagem:space-marines:stormlance-task-force:000008487006', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:space-marines:stormlance-task-force:000008487006', 'space-marines', 'stormlance-task-force', '000008487006', 'RIDE HARD, RIDE FAST', 1, 'battle_tactic', "Your opponent's Shooting phase, just after an enemy unit has selected its targets.", "One ADEPTUS ASTARTES MOUNTED or ADEPTUS ASTARTES FLY VEHICLE unit from your army that was selected as the target of one or more of the attacking unit's attacks.", 'Until the end of the phase, each time an attack targets your unit, subtract 1 from the Hit roll and subtract 1 from the Wound roll.', 'matched play same stratagem per phase', 'after_unit_selected_as_target', ('shooting',), 'friendly_unit', 'selected_target_unit', ('FLY', 'MOUNTED', 'VEHICLE',), (), (), (), (), 'b539eb9cd2901224ba1da3e2a60bb7480b7b40ff80f7324d5ed44421a4ae212d'),
