    SourceStratagemActivationProfile('phase17s:stratagem:space-marines:vanguard-spearhead:000008491002', 'stratagem:space-marines:vanguard-spearhead:000008491002', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:space-marines:vanguard-spearhead:000008491002', 'space-marines', 'vanguard-spearhead', '000008491002', 'A DEADLY PRIZE', 1, 'wargear', 'Start of the Command phase.', 'One ADEPTUS ASTARTES INFANTRY or ADEPTUS ASTARTES MOUNTED unit from your army within range of an objective marker you control.', 'That objective marker is said to be Sabotaged, and remains under your control even if you have no models within range of it, until your opponent controls it at the start or end of any turn. While an objective marker is Sabotaged and under your control, each time an enemy unit ends a Normal, Advance, Fall Back or Charge move within range of that objective marker, roll one D6: on a 2+, that enemy unit suffers D3 mortal wounds.', 'matched play same stratagem per phase', 'start_phase', ('command',), 'friendly_unit', 'friendly_unit', ('INFANTRY', 'MOUNTED',), (), (), (), (), 'b0ee3fa03c81ce7136c180602532e62ff1b90f98e7bd1c4f783dd647b8b6b164'),
    SourceStratagemActivationProfile('phase17s:stratagem:space-marines:vanguard-spearhead:000008491003', 'stratagem:space-marines:vanguard-spearhead:000008491003', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:space-marines:vanguard-spearhead:000008491003', 'space-marines', 'vanguard-spearhead', '000008491003', 'ARMOUR OF CONTEMPT', 1, 'battle_tactic', "Your opponent's Shooting phase or the Fight phase, just after an enemy unit has selected its targets.", "One ADEPTUS ASTARTES unit from your army that was selected as the target of one or more of the attacking unit's attacks.", 'Until the attacking unit has finished making its attacks, each time an attack targets your unit, worsen the Armour Penetration characteristic of that attack by 1.', 'matched play same stratagem per phase', 'after_unit_selected_as_target', ('shooting', 'fight',), 'friendly_unit', 'selected_target_unit', (), (), (), (), (), 'ae7a8092a172405bc8ce0ec6b350180488ce0d44268b1e9fd6d2d54bce5b71bb'),
