    SourceStratagemActivationProfile('phase17s:stratagem:tau-empire:kauyon:000008443007', 'stratagem:tau-empire:kauyon:000008443007', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:tau-empire:kauyon:000008443007', 'tau-empire', 'kauyon', '000008443007', 'WALL OF MIRRORS', 1, 'battle_tactic', "End of your opponent's Fight phase.", 'One Stealth, Ghostkeel or Commander Shadowsun unit from your army.', 'Remove your unit from the battlefield and place it into Strategic Reserves. RESTRICTIONS: You cannot target a unit that is within Engagement Range of one or more enemy units.', 'matched play same stratagem per phase', 'end_phase', ('fight',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), 'c810b3c20ed7a8728ae14922ca531f25b2bcbf7fcfd0234d5c12f3f39f9a1698'),
    SourceStratagemActivationProfile('phase17s:stratagem:tau-empire:kroot-hunting-pack:000008822002', 'stratagem:tau-empire:kroot-hunting-pack:000008822002', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:tau-empire:kroot-hunting-pack:000008822002', 'tau-empire', 'kroot-hunting-pack', '000008822002', 'JOIN THE HUNT', 2, 'battle_tactic', 'Any phase.', 'One Kroot Infantry or Kroot Hounds unit from your army that was just destroyed. You can use this Stratagem on that unit even though it was just destroyed.', 'Add a new unit to your army identical to your destroyed unit, in Strategic Reserves, at its Starting Strength. RESTRICTIONS: This Stratagem cannot be used to return destroyed Character units to Attached units. You can only use this Stratagem once per battle.', 'matched play same stratagem per phase', 'start_phase', ('any',), 'friendly_unit', 'friendly_unit', ('INFANTRY',), (), (), (), (), '33aa81e4ab4d23408412e773c0735ddb38b67d5281f4955bdf9faa3596e6fa7b'),
    SourceStratagemActivationProfile('phase17s:stratagem:tau-empire:kroot-hunting-pack:000008822003', 'stratagem:tau-empire:kroot-hunting-pack:000008822003', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:tau-empire:kroot-hunting-pack:000008822003', 'tau-empire', 'kroot-hunting-pack', '000008822003', 'A TRAP WELL LAID', 1, 'battle_tactic', 'Your Shooting phase or the Fight phase.', 'One Kroot unit from your army that has not been selected to shoot or fight this phase.', 'After your unit has resolved its attacks this phase, select one enemy unit that was hit by one or more of those attacks. Until the end of the phase, each time a KROOT model from your army makes an attack that targets that enemy unit, unless the attacking unit is Battle-shocked, improve the Armour Penetration characteristic of that attack by 1.', 'matched play same stratagem per phase', 'start_phase', ('shooting', 'fight',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), 'bef1f10817bc2c83c06db18671555d61c2c3e0acf4b07c24391182674051b545'),
