    SourceStratagemActivationProfile('phase17s:stratagem:thousand-sons:grand-coven:000010194004', 'stratagem:thousand-sons:grand-coven:000010194004', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:thousand-sons:grand-coven:000010194004', 'thousand-sons', 'grand-coven', '000010194004', 'EGOTISTICAL POWER', 1, 'strategic_ploy', 'Your Command phase.', 'One Thousand Sons Psyker unit from your army.', 'Select the Imbued Manifestation, Psychic Maelstrom or Wrath of the Immaterium ability. Until the start of your next Command phase, that ability applies to your unit instead of any other Kindred Sorcery ability, even if you have already selected that ability this battle.', 'matched play same stratagem per phase', 'start_phase', ('command',), 'friendly_unit', 'friendly_unit', ('PSYKER',), (), (), (), (), 'b84a922ea8cd3b7ef9ae6b403dfa0d97beb8b01339063ef927dd18dceaf1bba5'),
    SourceStratagemActivationProfile('phase17s:stratagem:thousand-sons:grand-coven:000010194005', 'stratagem:thousand-sons:grand-coven:000010194005', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:thousand-sons:grand-coven:000010194005', 'thousand-sons', 'grand-coven', '000010194005', 'DESECRATION OF WORLDS', 1, 'epic_deed', 'Your Command phase.', 'One Thousand Sons Psyker unit from your army within range of an objective marker you control.', "That objective marker remains under your control until your opponent's Level of Control over that objective marker is greater than yours at the end of a phase.", 'matched play same stratagem per phase', 'start_phase', ('command',), 'friendly_unit', 'friendly_unit', ('PSYKER',), (), (), (), (), '7820417295f52f3ba2751c926b73abd5f1c75394f93c68dfaf3c4f1b68f10541'),
    SourceStratagemActivationProfile('phase17s:stratagem:thousand-sons:grand-coven:000010194006', 'stratagem:thousand-sons:grand-coven:000010194006', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:thousand-sons:grand-coven:000010194006', 'thousand-sons', 'grand-coven', '000010194006', 'ARCANE FOCUS', 1, 'epic_deed', 'Your Shooting phase, just after you take a Psychic test for a Thousand Sons model from your army that Channelled the Warp (before resolving that Ritual).', 'That THOUSAND SONS model.', 'Re-roll all of the D6 rolled for that Psychic test (including the additional D6 for Channelling the Warp).', 'matched play same stratagem per phase', 'start_phase', ('shooting',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), '0c249c3c416ba3381c53cedb7619e0b71e8b50d474ffb0722ab4210a0b6bdaa5'),
    SourceStratagemActivationProfile('phase17s:stratagem:thousand-sons:grand-coven:000010194007', 'stratagem:thousand-sons:grand-coven:000010194007', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:thousand-sons:grand-coven:000010194007', 'thousand-sons', 'grand-coven', '000010194007', 'DEVASTATING SORCERY', 2, 'battle_tactic', 'Your Shooting phase.', 'One Thousand Sons Psyker unit from your army that has not been selected to shoot this phase.', 'Until the end of the phase, add 9" to the Range characteristic of Psychic weapons equipped by models in your unit, and each time a model in your unit makes an attack with a Psychic weapon, you can re-roll the Hit roll and you can re-roll the Wound roll.', 'matched play same stratagem per phase', 'start_phase', ('shooting',), 'friendly_unit', 'not_selected_to_shoot_unit', ('PSYKER',), (), (), (), (), '14ffbf6d3c3f7ca973685340a660292c560a278e2b4718316aac72864bdff79c'),
    SourceStratagemActivationProfile('phase17s:stratagem:thousand-sons:hexwarp-thrallband:000009742002', 'stratagem:thousand-sons:hexwarp-thrallband:000009742002', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:thousand-sons:hexwarp-thrallband:000009742002', 'thousand-sons', 'hexwarp-thrallband', '000009742002', 'WARDING HEX', 1, 'epic_deed', 'Command phase.', "One Thousand Sons Psyker unit from your army within range of an objective marker you control, if that objective marker is wholly within your army's Flow of Magic.", "That objective marker remains under your control until your opponent's Level of Control over that objective marker is greater than yours at the end of a phase.", 'matched play same stratagem per phase', 'start_phase', ('command',), 'friendly_unit', 'friendly_unit', ('PSYKER',), (), (), (), (), 'c156b22fed31f75888e628b004680f181d9fdfc4908c5a5c7ca2038cb835b3a7'),
    SourceStratagemActivationProfile('phase17s:stratagem:thousand-sons:hexwarp-thrallband:000009742003', 'stratagem:thousand-sons:hexwarp-thrallband:000009742003', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:thousand-sons:hexwarp-thrallband:000009742003', 'thousand-sons', 'hexwarp-thrallband', '000009742003', 'WRATH OF THE DOOMED', 1, 'strategic_ploy', 'Fight phase, just after an enemy unit has selected its targets.', "One THOUSAND SONS unit from your army that was selected as the target of one or more of the attacking unit's attacks.", "Until the end of the phase, each time a model in your unit is destroyed, if that model has not fought this phase, roll one D6, adding 1 to the result if your unit is wholly within your army's Flow of Magic: on a 4+, do not remove it from play. That destroyed model can fight after the attacking unit has finished making its attacks, and is then removed from play.", 'matched play same stratagem per phase', 'after_unit_selected_as_target', ('fight',), 'friendly_unit', 'selected_target_unit', (), (), (), (), (), '5c948a21a3c7b7d967ff9da082f4a6d298cab33e105ef43330661a9addd2f320'),
    SourceStratagemActivationProfile('phase17s:stratagem:thousand-sons:hexwarp-thrallband:000009742004', 'stratagem:thousand-sons:hexwarp-thrallband:000009742004', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:thousand-sons:hexwarp-thrallband:000009742004', 'thousand-sons', 'hexwarp-thrallband', '000009742004', 'STRANDS OF TIME', 1, 'strategic_ploy', 'Your Movement phase, just after a THOUSAND SONS PSYKER unit from your army Falls Back.', 'That Thousand Sons Psyker unit.', "Until the end of the turn, your unit is eligible to shoot or declare a charge in a turn in which it Fell Back. If your unit is wholly within your army's Flow of Magic when it is targeted with this Stratagem, then until the end of the turn, your unit is eligible to shoot and declare a charge in a turn in which it Fell Back.", 'matched play same stratagem per phase', 'start_phase', ('movement',), 'friendly_unit', 'friendly_unit', ('PSYKER',), (), (), (), (), '8b12d73e5b95072c30e0251354cdbfad1a11d34722a376caf77e75e075c621df'),
    SourceStratagemActivationProfile('phase17s:stratagem:thousand-sons:hexwarp-thrallband:000009742005', 'stratagem:thousand-sons:hexwarp-thrallband:000009742005', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:thousand-sons:hexwarp-thrallband:000009742005', 'thousand-sons', 'hexwarp-thrallband', '000009742005', 'THROUGH THE VEIL', 1, 'epic_deed', 'Start of the Reinforcements step of your Movement phase.', 'One Rubric Marines or Scarab Occult Terminators unit from your army that is in Strategic Reserves.', 'If it is a RUBRIC MARINES unit, until the end of the phase, it has the Deep Strike ability. When your unit is set up on the battlefield using the Deep Strike ability, if it is a SCARAB OCCULT TERMINATOR unit it can be set up anywhere on the battlefield that is wholly within your army\'s Flow of Magic and more than 6" horizontally away from all enemy models. RESTRICTIONS: If a SCARAB OCCULT TERMINATORS unit is targeted with this Stratagem, it is not eligible to declare a charge in the same turn.', 'matched play same stratagem per phase', 'start_phase', ('movement',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), 'b4135ea282a5578d199aaf5f8ef04f33a88d168c9dcfeab7076590dd732857f1'),
    SourceStratagemActivationProfile('phase17s:stratagem:thousand-sons:hexwarp-thrallband:000009742006', 'stratagem:thousand-sons:hexwarp-thrallband:000009742006', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:thousand-sons:hexwarp-thrallband:000009742006', 'thousand-sons', 'hexwarp-thrallband', '000009742006', 'SCOURING WARPFLAME', 1, 'strategic_ploy', 'Your Shooting phase.', "One Thousand Sons Psyker unit from your army that has not been selected to shoot this phase and is wholly within your army's Flow of Magic.", 'Until the end of the phase, ranged weapons equipped by models in your unit have the [IGNORES COVER] ability. After your unit has shot this phase, select one enemy unit hit by one or more of those attacks. Until the end of the phase, models in that unit cannot have the Benefit of Cover.', 'matched play same stratagem per phase', 'start_phase', ('shooting',), 'friendly_unit', 'not_selected_to_shoot_unit', ('PSYKER',), (), (), (), (), '27c071d590d8c32435c1897914221f39d0e7ff9cd1cebd8b1481538217f23f24'),
    SourceStratagemActivationProfile('phase17s:stratagem:thousand-sons:hexwarp-thrallband:000009742007', 'stratagem:thousand-sons:hexwarp-thrallband:000009742007', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:thousand-sons:hexwarp-thrallband:000009742007', 'thousand-sons', 'hexwarp-thrallband', '000009742007', 'KALEIDOSCOPIC TEMPEST', 1, 'battle_tactic', "Your opponent's Shooting phase, just after an enemy unit has selected its targets.", "One Thousand Sons Psyker unit from your army that was selected as the target of one or more of the attacking unit's attacks.", "Until the end of the phase, your unit has the Stealth ability, and, if your unit is wholly within your army's Flow of Magic, each time an attack targets your unit, it has the Benefit of Cover against that attack.", 'matched play same stratagem per phase', 'after_unit_selected_as_target', ('shooting',), 'friendly_unit', 'selected_target_unit', ('PSYKER',), (), (), (), (), '3a158104026be97ee279e09b30fefc4bef3f0d394b05027c2501f5b2fa232406'),
