    SourceStratagemActivationProfile('phase17s:stratagem:thousand-sons:rubricae-phalanx:000010206005', 'stratagem:thousand-sons:rubricae-phalanx:000010206005', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:thousand-sons:rubricae-phalanx:000010206005', 'thousand-sons', 'rubricae-phalanx', '000010206005', 'REVENGE OF THE RUBRICAE', 1, 'strategic_ploy', "Your opponent's Shooting phase, just after a Thousand Sons Psyker model from your army is destroyed.", 'One Rubricae unit from your army that was within 6" of that PSYKER model when it was destroyed.', 'After the attacking unit has shot, your RUBRICAE unit can shoot as if it were your Shooting phase, but when resolving those attacks it can only target the enemy unit that just destroyed your PSYKER model (and only if it is an eligible target).', 'matched play same stratagem per phase', 'start_phase', ('shooting',), 'friendly_unit', 'friendly_unit', ('PSYKER',), (), (), (), (), 'beafa549ddc30a6432a911c949caf77d1fabaf8581a7bf475e37520fd9ae155c'),
    SourceStratagemActivationProfile('phase17s:stratagem:thousand-sons:rubricae-phalanx:000010206006', 'stratagem:thousand-sons:rubricae-phalanx:000010206006', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:thousand-sons:rubricae-phalanx:000010206006', 'thousand-sons', 'rubricae-phalanx', '000010206006', 'IMPLACABLE GUARDIANS', 2, 'strategic_ploy', "Your opponent's Shooting phase, just after an enemy unit has selected its targets.", "One Rubric Marines Psyker unit from your army that was selected as the target of one or more of the attacking unit's attacks.", 'Until the end of the phase, each time an attack is allocated to a model in your unit (excluding PSYKER models), subtract 1 from the Damage characteristic of that attack.', 'matched play same stratagem per phase', 'after_unit_selected_as_target', ('shooting',), 'friendly_unit', 'selected_target_unit', ('PSYKER',), (), (), (), (), '348a0f699d14bf6aa2f76ace8d92f41bb7f97185239f80e3a6c863c6eb50de73'),
    SourceStratagemActivationProfile('phase17s:stratagem:thousand-sons:rubricae-phalanx:000010206007', 'stratagem:thousand-sons:rubricae-phalanx:000010206007', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:thousand-sons:rubricae-phalanx:000010206007', 'thousand-sons', 'rubricae-phalanx', '000010206007', 'UNWAVERING PHALANX', 1, 'battle_tactic', "Your opponent's Charge phase, just after an enemy unit ends a Charge move.", 'One Rubric Marines unit from your army within Engagement Range of that enemy unit.', 'Until the end of the turn, each time an attack targets your unit, subtract 1 from the Wound roll.', 'matched play same stratagem per phase', 'after_unit_ends_charge_move', ('charge',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), '5fd21547a95e91dda89de7f3ee4ebe5ba98f64af1669e708fc8bbb3a4c0043f7'),
    SourceStratagemActivationProfile('phase17s:stratagem:thousand-sons:warpforged-cabal:000010210002', 'stratagem:thousand-sons:warpforged-cabal:000010210002', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:thousand-sons:warpforged-cabal:000010210002', 'thousand-sons', 'warpforged-cabal', '000010210002', 'HEX-MARKED ARMOUR', 1, 'battle_tactic', "Your opponent's Shooting phase or the Fight phase, just after an enemy unit has selected its targets.", "One Thousand Sons Vehicle unit from your army that was selected as the target of one or more of the attacking unit's attacks.", 'Until the attacking unit has finished making its attacks, each time an attack targets your unit, worsen the Armour Penetration characteristic of that attack by 1.', 'matched play same stratagem per phase', 'after_unit_selected_as_target', ('shooting', 'fight',), 'friendly_unit', 'selected_target_unit', ('VEHICLE',), (), (), (), (), '2708de16ddb4b35c1969489e41e36c5fafbf5b49fd2c67f6d0c399d80390e396'),
    SourceStratagemActivationProfile('phase17s:stratagem:thousand-sons:warpforged-cabal:000010210003', 'stratagem:thousand-sons:warpforged-cabal:000010210003', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:thousand-sons:warpforged-cabal:000010210003', 'thousand-sons', 'warpforged-cabal', '000010210003', 'MUTATE LANDSCAPE', 1, 'epic_deed', 'Your Command phase.', 'One Thousand Sons Psyker unit from your army within range of an objective marker you control.', "That objective marker is mutated, and remains under your control until your opponent's Level of Control over that objective marker is greater than yours at the end of a phase. While an objective marker is mutated and under your control, each time an enemy unit ends a Normal, Advance, Fall Back or Charge move within range of that objective marker, roll one D6: on a 4+, that enemy unit suffers D3 mortal wounds.", 'matched play same stratagem per phase', 'start_phase', ('command',), 'friendly_unit', 'friendly_unit', ('PSYKER',), (), (), (), (), '6e611136d8909b63d74277dda8b3a3301fe3990490a573afaeaee4a38483cb01'),
    SourceStratagemActivationProfile('phase17s:stratagem:thousand-sons:warpforged-cabal:000010210004', 'stratagem:thousand-sons:warpforged-cabal:000010210004', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:thousand-sons:warpforged-cabal:000010210004', 'thousand-sons', 'warpforged-cabal', '000010210004', 'CYBERSPIRIT MACHINATIONS', 1, 'strategic_ploy', 'Your Movement phase, just after a Thousand Sons Vehicle unit from your army Falls Back.', 'That VEHICLE unit, and one friendly Thousand Sons Psyker unit within 6" of that VEHICLE unit.', 'Until the end of the turn, your VEHICLE unit is eligible to shoot and declare a charge in a turn in which it Fell Back.', 'matched play same stratagem per phase', 'start_phase', ('movement',), 'friendly_unit', 'friendly_unit', ('PSYKER', 'VEHICLE',), (), (), (), (), '67e7793523d3826a6e779058212f9e644d476eabd7c5385da42fae1be9f1d909'),
    SourceStratagemActivationProfile('phase17s:stratagem:thousand-sons:warpforged-cabal:000010210005', 'stratagem:thousand-sons:warpforged-cabal:000010210005', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:thousand-sons:warpforged-cabal:000010210005', 'thousand-sons', 'warpforged-cabal', '000010210005', 'MALEVOLENT ANIMUS', 1, 'epic_deed', 'Your Command phase.', 'One Thousand Sons Vehicle unit from your army within 6" of one or more friendly Thousand Sons Psyker units.', 'Until the start of your next Command phase, your VEHICLE unit is malevolent. While a unit is malevolent, it can ignore any or all modifiers to the following: the profile characteristics of its models; the Weapon Skill and Ballistic Skill characteristics of weapons equipped by its models; any roll or test made for it (excluding modifiers to saving throws).', 'matched play same stratagem per phase', 'start_phase', ('command',), 'friendly_unit', 'friendly_unit', ('PSYKER', 'VEHICLE',), (), (), (), (), 'a4faa959ac2969cbdb129d722c18d6d663246930ba1e9d98af58c6ecc0a9ae71'),
    SourceStratagemActivationProfile('phase17s:stratagem:thousand-sons:warpforged-cabal:000010210006', 'stratagem:thousand-sons:warpforged-cabal:000010210006', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:thousand-sons:warpforged-cabal:000010210006', 'thousand-sons', 'warpforged-cabal', '000010210006', 'ENSORCELLED INFUSION', 1, 'battle_tactic', 'Your Shooting phase.', 'One Thousand Sons Vehicle unit from your army that has not been selected to shoot this phase, that is within 6" of one or more friendly Thousand Sons Psyker units.', 'Until the end of the phase, ranged weapons equipped by VEHICLE models in your unit have the [PSYCHIC] ability and each time an attack is made with such a weapon, add 1 to the Wound roll.', 'matched play same stratagem per phase', 'start_phase', ('shooting',), 'friendly_unit', 'not_selected_to_shoot_unit', ('PSYKER', 'VEHICLE',), (), (), (), (), 'd5c226a03ea5d59999b61ebd990472c406fd332af466e7939cc84afea0eb1f1b'),
    SourceStratagemActivationProfile('phase17s:stratagem:thousand-sons:warpforged-cabal:000010210007', 'stratagem:thousand-sons:warpforged-cabal:000010210007', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:thousand-sons:warpforged-cabal:000010210007', 'thousand-sons', 'warpforged-cabal', '000010210007', 'WARPFLAME GARGOYLES', 1, 'wargear', "Your opponent's Charge phase, just after an enemy unit ends a Charge move.", 'One Thousand Sons Vehicle unit from your army within Engagement Range of that enemy unit.', 'Roll six D6: for each 5+, that enemy unit suffers 1 mortal wound. That enemy unit must then take a Battle-shock test.', 'matched play same stratagem per phase', 'after_unit_ends_charge_move', ('charge',), 'friendly_unit', 'friendly_unit', ('VEHICLE',), (), (), (), (), '24b219816c2b96c875825a5c2b0e6e95f58a2c7e6f831c179caa021eedc913a8'),
    SourceStratagemActivationProfile('phase17s:stratagem:thousand-sons:warpmeld-pact:000010202002', 'stratagem:thousand-sons:warpmeld-pact:000010202002', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:thousand-sons:warpmeld-pact:000010202002', 'thousand-sons', 'warpmeld-pact', '000010202002', 'GIFT OF CHANGE', 1, 'epic_deed', 'Any phase.', 'One Thousand Sons Character model from your army (excluding Monsters) that was just destroyed. You can use this Stratagem on that model even though it was just destroyed.', 'At the end of the phase, add one Tzeentch Chaos Spawn unit containing one model to your army, and set it up as close as possible to where your model was destroyed and not within Engagement Range of one or more enemy units. RESTRICTIONS: You can only use this Stratagem once per battle round.', 'matched play same stratagem per phase', 'start_phase', ('any',), 'friendly_unit', 'friendly_unit', ('CHARACTER',), (), (), ('MONSTERS',), (), 'a11b946d20f4462312e213b0cc00bf4c820b488544b40afbbd7027cbdde33ba6'),
    SourceStratagemActivationProfile('phase17s:stratagem:thousand-sons:warpmeld-pact:000010202003', 'stratagem:thousand-sons:warpmeld-pact:000010202003', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:thousand-sons:warpmeld-pact:000010202003', 'thousand-sons', 'warpmeld-pact', '000010202003', 'WARPED VICISSITUDE', 1, 'strategic_ploy', "Your opponent's Shooting phase or the Fight phase, just after an enemy unit has selected its targets.", "One Tzaangors unit from your army that was selected as the target of one or more of the attacking unit's attacks.", 'Until the end of the phase, models in your unit have a 4+ invulnerable save.', 'matched play same stratagem per phase', 'after_unit_selected_as_target', ('shooting', 'fight',), 'friendly_unit', 'selected_target_unit', (), (), (), (), (), 'b7d3fd683330fe7a794e4ac2c6fd7a052a5fd9dda55f203e89e5c24a599884fc'),
    SourceStratagemActivationProfile('phase17s:stratagem:thousand-sons:warpmeld-pact:000010202004', 'stratagem:thousand-sons:warpmeld-pact:000010202004', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:thousand-sons:warpmeld-pact:000010202004', 'thousand-sons', 'warpmeld-pact', '000010202004', 'DERANGED FEROCITY', 1, 'strategic_ploy', 'Fight phase, just after a Tzeentch Mutant unit from your army is selected to fight.', 'That TZEENTCH MUTANT unit.', 'Until the end of the phase, each time a model in your unit makes a Pile-in or Consolidation move, it can move up to 6" instead of up to 3", and when determining which models in it are eligible to fight, any models in it that are within 3" of one or more enemy models are eligible to fight. When resolving those attacks, such models can target one of those enemy units that is within 3" of them and within Engagement Range of their unit.', 'matched play same stratagem per phase', 'just_after_friendly_unit_selected_to_fight', ('fight',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), '9efcdc1f334014227c4997b310529a4190d50452b602531020b5d8537365ded3'),
    SourceStratagemActivationProfile('phase17s:stratagem:thousand-sons:warpmeld-pact:000010202005', 'stratagem:thousand-sons:warpmeld-pact:000010202005', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:thousand-sons:warpmeld-pact:000010202005', 'thousand-sons', 'warpmeld-pact', '000010202005', 'BLESSED TRANSMUTATIONS', 1, 'strategic_ploy', 'Your Command phase.', 'One Thousand Sons Psyker model from your army, and one friendly Tzaangors unit that is below its Starting Strength and within 12" of that PSYKER model.', 'Return up to D3+1 destroyed models (excluding Characters) to your TZAANGORS unit.', 'matched play same stratagem per phase', 'start_phase', ('command',), 'friendly_unit', 'friendly_unit', ('PSYKER',), (), (), (), (), '21b1ddc49c30061aee1b7c49130fb931528d36826172ed26bb9d11e6d7bae823'),
    SourceStratagemActivationProfile('phase17s:stratagem:thousand-sons:warpmeld-pact:000010202006', 'stratagem:thousand-sons:warpmeld-pact:000010202006', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:thousand-sons:warpmeld-pact:000010202006', 'thousand-sons', 'warpmeld-pact', '000010202006', 'TOUCHED BY TZEENTCH', 1, 'strategic_ploy', 'Start of your Movement phase.', 'One Tzeentch Mutant unit from your army.', 'Until the end of the turn, your unit is eligible to shoot or declare a charge in a turn in which it Advanced.', 'matched play same stratagem per phase', 'start_phase', ('movement',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), '4fd0cf1d3d59ec77bb96f3d68239d11a1034aabde1af71ae6a7d25b686a71e9d'),
    SourceStratagemActivationProfile('phase17s:stratagem:thousand-sons:warpmeld-pact:000010202007', 'stratagem:thousand-sons:warpmeld-pact:000010202007', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:thousand-sons:warpmeld-pact:000010202007', 'thousand-sons', 'warpmeld-pact', '000010202007', 'TWISTED MIRAGE', 1, 'strategic_ploy', 'Reinforcements step of your Movement phase.', 'One Tzeentch Mutant unit from your army that is arriving from Strategic Reserves this phase.', 'Your unit can be set up anywhere on the battlefield that is more than 6" horizontally away from all enemy units, or anywhere on the battlefield that is more than 9" horizontally away from all enemy units if it is a Monster unit. In either case, until the end of the turn, it is not eligible to declare a charge.', 'matched play same stratagem per phase', 'start_phase', ('movement',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), 'fb684681c3f4b33a8270cd7ef160d4a4df9c4ac61a4d31a932d2d0c1b9b44e19'),
    SourceStratagemActivationProfile('phase17s:stratagem:tyranids:assimilation-swarm:000008413002', 'stratagem:tyranids:assimilation-swarm:000008413002', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:tyranids:assimilation-swarm:000008413002', 'tyranids', 'assimilation-swarm', '000008413002', 'BROODGUARD IMPULSE', 1, 'epic_deed', 'Any phase.', 'One Harvester unit from your army that was just destroyed. You can use this Stratagem on that unit even though it was just destroyed.', 'Until the end of the battle, each time a friendly TYRANIDS model makes an attack that targets the enemy unit that just destroyed your HARVESTER unit, add 1 to the Wound roll.', 'matched play same stratagem per phase', 'start_phase', ('any',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), '7db01fc547474417da8fe57ca7f5b108057beeae26dfd7e485470d40ebd6de2f'),
    SourceStratagemActivationProfile('phase17s:stratagem:tyranids:assimilation-swarm:000008413003', 'stratagem:tyranids:assimilation-swarm:000008413003', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:tyranids:assimilation-swarm:000008413003', 'tyranids', 'assimilation-swarm', '000008413003', 'RECLAIM BIOMASS', 1, 'strategic_ploy', 'Any phase, when a TYRANIDS unit from your army is destroyed, before the last model in it is removed from play.', 'One Harvester unit from your army that is within 6" of that destroyed unit.', 'Regenerate one friendly TYRANIDS unit within 6" of your HARVESTER unit (See Feed the Swarm).', 'matched play same stratagem per phase', 'start_phase', ('any',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), '7a2aa272a90bbe2a896e77eb434474b60c369aa4011e3c8cb8d5cbd47bd47aa0'),
