    SourceStratagemActivationProfile('phase17s:stratagem:tyranids:assimilation-swarm:000008413006', 'stratagem:tyranids:assimilation-swarm:000008413006', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:tyranids:assimilation-swarm:000008413006', 'tyranids', 'assimilation-swarm', '000008413006', 'SECURE BIOMASS', 1, 'strategic_ploy', 'Fight phase.', 'One TYRANIDS unit from your army that has not been selected to fight this phase.', 'Until the end of the phase, melee weapons equipped by models in your unit have the [LETHAL HITS] ability. If your unit is a Harvester unit, each time a model in that unit makes a melee attack, a successful unmodified Hit roll of 5+ scores a Critical Hit as well.', 'matched play same stratagem per phase', 'start_phase', ('fight',), 'friendly_unit', 'not_selected_to_fight_unit', (), (), (), (), (), '8fb2c9fc8de567daefcf379fe1e23002811b7092954601b0c8ddd2dcffac3235'),
    SourceStratagemActivationProfile('phase17s:stratagem:tyranids:assimilation-swarm:000008413007', 'stratagem:tyranids:assimilation-swarm:000008413007', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:tyranids:assimilation-swarm:000008413007', 'tyranids', 'assimilation-swarm', '000008413007', 'RAPACIOUS HUNGER', 1, 'battle_tactic', 'Your Fight phase.', 'One TYRANIDS unit from your army that just destroyed an enemy unit.', 'Your unit immediately Regenerates (See Feed the Swarm). When doing so, if your unit is a Harvester unit and you choose for one model to regain up to D3 lost wounds, that model regains up to 3 lost wounds instead.', 'matched play same stratagem per phase', 'start_phase', ('fight',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), 'fc25a40738368c40f60496f4964a965d9bcd79ca61976d99e27b54ebd84827f6'),
    SourceStratagemActivationProfile('phase17s:stratagem:tyranids:crusher-stampede:000008422002', 'stratagem:tyranids:crusher-stampede:000008422002', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:tyranids:crusher-stampede:000008422002', 'tyranids', 'crusher-stampede', '000008422002', 'CORROSIVE VISCERA', 1, 'strategic_ploy', "Your opponent's Shooting phase or the Fight phase, just after a Tyranids Monster model from your army with the Deadly Demise ability that cannot FLY is destroyed.", 'That TYRANIDS MONSTER model. You can use this Stratagem on that model even though it was just destroyed.', "Do not roll one D6 to determine whether mortal wounds are inflicted by your model's Deadly Demise ability. Instead, mortal wounds are automatically inflicted.", 'matched play same stratagem per phase', 'start_phase', ('shooting', 'fight',), 'friendly_unit', 'friendly_unit', ('MONSTER',), (), (), (), (), '781303d7a77b24379d95cb9fd17690cf1c467014b9a4d99a43c02aba9b802b68'),
    SourceStratagemActivationProfile('phase17s:stratagem:tyranids:crusher-stampede:000008422003', 'stratagem:tyranids:crusher-stampede:000008422003', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:tyranids:crusher-stampede:000008422003', 'tyranids', 'crusher-stampede', '000008422003', 'RAMPAGING MONSTROSITIES', 1, 'battle_tactic', 'Fight phase.', 'One Tyranids Monster unit from your army that has not been selected to fight this phase.', 'Until the end of the phase, each time a model in your unit makes an attack, you can re-roll the Hit roll.', 'matched play same stratagem per phase', 'start_phase', ('fight',), 'friendly_unit', 'not_selected_to_fight_unit', ('MONSTER',), (), (), (), (), 'ffeb1d9bb8fd91860ab84c5a092083017ad4c4e54b827490d55997481f739139'),
    SourceStratagemActivationProfile('phase17s:stratagem:tyranids:crusher-stampede:000008422004', 'stratagem:tyranids:crusher-stampede:000008422004', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:tyranids:crusher-stampede:000008422004', 'tyranids', 'crusher-stampede', '000008422004', 'SAVAGE ROAR', 1, 'battle_tactic', 'Fight phase, just after an enemy unit has selected its targets.', "One Tyranids Monster unit from your army that was selected as the target of one or more of the attacking unit's attacks.", 'That enemy unit must take a Battle-shock test and, until the end of the phase, each time a model in that enemy unit makes an attack that targets your unit, subtract 1 from the Hit roll. If that Battle-shock test was failed, subtract 1 from the Wound roll as well.', 'matched play same stratagem per phase', 'after_unit_selected_as_target', ('fight',), 'friendly_unit', 'selected_target_unit', ('MONSTER',), (), (), (), (), '2ca524c7425c2bfa126601ff99e30af50aa83b2a941515e4a68e79ef238579ee'),
    SourceStratagemActivationProfile('phase17s:stratagem:tyranids:crusher-stampede:000008422005', 'stratagem:tyranids:crusher-stampede:000008422005', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:tyranids:crusher-stampede:000008422005', 'tyranids', 'crusher-stampede', '000008422005', 'UNTRAMMELLED FEROCITY', 1, 'strategic_ploy', 'Your Movement phase.', 'One Tyranids Monster unit from your army that has not been selected to move this phase.', 'Until the end of the phase, each time a model in your unit makes a Normal, Advance or Fall Back move, it can move through models (excluding TITANIC models) and sections of terrain features that are 4" or less in height. When doing so: - It can move within Engagement Range of enemy models, but cannot end that move within Engagement Range of them. - It can also move through sections of terrain features that are more than 4" in height, but if it does, after its unit has moved, roll one D6: on a 1, your unit is Battle-shocked.', 'matched play same stratagem per phase', 'start_phase', ('movement',), 'friendly_unit', 'selected_to_move_unit', ('MONSTER',), (), (), (), (), 'd881050aa342f7de73f512a49166596ed03d57068317e55127befbd2fa2ccad2'),
    SourceStratagemActivationProfile('phase17s:stratagem:tyranids:crusher-stampede:000008422006', 'stratagem:tyranids:crusher-stampede:000008422006', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:tyranids:crusher-stampede:000008422006', 'tyranids', 'crusher-stampede', '000008422006', 'SWARM-GUIDED SALVOES', 1, 'battle_tactic', 'Your Shooting phase.', 'One Tyranids Monster unit from your army that has not been selected to shoot this phase.', "Until the end of the phase, ranged weapons equipped by models in your unit have the [IGNORES COVER] ability, and until the end of the phase each time a model in your unit makes an attack, you can ignore any or all modifiers to that model's Ballistic Skill characteristic and any or all modifiers to the Hit roll.", 'matched play same stratagem per phase', 'start_phase', ('shooting',), 'friendly_unit', 'not_selected_to_shoot_unit', ('MONSTER',), (), (), (), (), 'dd0907b9518df9ec6ab31fc164fffebeb305b203d3f8f9ebe992e41ed2dd499b'),
    SourceStratagemActivationProfile('phase17s:stratagem:tyranids:crusher-stampede:000008422007', 'stratagem:tyranids:crusher-stampede:000008422007', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:tyranids:crusher-stampede:000008422007', 'tyranids', 'crusher-stampede', '000008422007', 'MASSIVE IMPACT', 1, 'epic_deed', 'Your Charge phase, just after a Tyranids Monster model from your army ends a Charge move.', 'That TYRANIDS MONSTER model.', 'Select one enemy unit within Engagement Range of your model and roll six D6: for each 4+, that enemy unit suffers 1 mortal wound.', 'matched play same stratagem per phase', 'after_unit_ends_charge_move', ('charge',), 'friendly_unit', 'friendly_unit', ('MONSTER',), (), (), (), (), 'fe05fcb069bad668772dbfecfdbbe8665ad409df4bf8509f141b3694ae9c8762'),
    SourceStratagemActivationProfile('phase17s:stratagem:tyranids:invasion-fleet:000008349002', 'stratagem:tyranids:invasion-fleet:000008349002', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:tyranids:invasion-fleet:000008349002', 'tyranids', 'invasion-fleet', '000008349002', 'RAPID REGENERATION', 1, 'battle_tactic', "Your opponent's Shooting phase or the Fight phase, just after an enemy unit has selected its targets.", "One TYRANIDS unit from your army that was selected as the target of one or more of the attacking unit's attacks.", 'Until the end of the phase, models in your unit have the Feel No Pain 6+ ability. If your unit is within Synapse Range of your army, models in your unit have the Feel No Pain 5+ ability instead.', 'matched play same stratagem per phase', 'after_unit_selected_as_target', ('shooting', 'fight',), 'friendly_unit', 'selected_target_unit', (), (), (), (), (), '47e2e5eca2bb3f2a4a1b77e9ed76ef95aa638a06c3e8b7f19552df166ec7605d'),
    SourceStratagemActivationProfile('phase17s:stratagem:tyranids:invasion-fleet:000008349003', 'stratagem:tyranids:invasion-fleet:000008349003', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:tyranids:invasion-fleet:000008349003', 'tyranids', 'invasion-fleet', '000008349003', 'ADRENAL SURGE', 2, 'battle_tactic', 'Fight phase.', 'Up to two TYRANIDS units from your army that are within Synapse Range of your army and are eligible to fight, or one other TYRANIDS unit from your army that is eligible to fight.', 'Until the end of the phase, each time a model in any of those selected units makes an attack, an unmodified Hit roll of 5+ scores a Critical Hit.', 'matched play same stratagem per phase', 'start_phase', ('fight',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), 'b2336cdfeeffe02dd5c097559c9582661292e7505fe9610cd063e04d0ad416cd'),
    SourceStratagemActivationProfile('phase17s:stratagem:tyranids:invasion-fleet:000008349004', 'stratagem:tyranids:invasion-fleet:000008349004', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:tyranids:invasion-fleet:000008349004', 'tyranids', 'invasion-fleet', '000008349004', 'DEATH FRENZY', 1, 'strategic_ploy', 'Fight phase, just after an enemy unit has selected its targets.', "One TYRANIDS unit from your army that was selected as the target of one or more of the attacking unit's attacks.", "Until the end of the phase, each time a model in your unit is destroyed, if that model has not fought this phase, roll one D6: on a 4+, do not remove it from play. The destroyed model can fight after the attacking model's unit has finished making its attacks, and is then removed from play.", 'matched play same stratagem per phase', 'after_unit_selected_as_target', ('fight',), 'friendly_unit', 'selected_target_unit', (), (), (), (), (), '8e12c057a4aa78e8dadf5c71b3bf34fb62bbd71fdef111d7bdb9453cf4ca3c02'),
    SourceStratagemActivationProfile('phase17s:stratagem:tyranids:invasion-fleet:000008349005', 'stratagem:tyranids:invasion-fleet:000008349005', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:tyranids:invasion-fleet:000008349005', 'tyranids', 'invasion-fleet', '000008349005', 'OVERRUN', 1, 'strategic_ploy', 'Fight phase, just before a TYRANIDS unit from your army Consolidates.', 'That TYRANIDS unit.', 'Until the end of the phase, each time your unit Consolidates, models in it can move an additional 3" as long as your unit can end that move within Engagement Range of one or more enemy units. If your unit is within Synapse Range of your army and not within Engagement Range of any enemy units, instead of making that Consolidation move, it can make a Normal move of up to 6".', 'matched play same stratagem per phase', 'start_phase', ('fight',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), 'd298495d68e0889bcef154d6cd444ef88698cbf1db9a7a6b52af0e5ce1e9db53'),
    SourceStratagemActivationProfile('phase17s:stratagem:tyranids:invasion-fleet:000008349006', 'stratagem:tyranids:invasion-fleet:000008349006', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:tyranids:invasion-fleet:000008349006', 'tyranids', 'invasion-fleet', '000008349006', 'PREDATORY IMPERATIVE', 1, 'strategic_ploy', 'Your Command phase.', 'Up to two TYRANIDS units from your army that are within Synapse Range of your army, or one other TYRANIDS unit from your army.', 'Select one Hyper-adaptation. Until the start of your next Command phase, that Hyper-adaptation is active for those selected units in addition to any other that may be active for your army. RESTRICTIONS: You cannot select the same Hyper-adaptation you selected at the start of the first battle round.', 'matched play same stratagem per phase', 'start_phase', ('command',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), '79d6d36461eb767ef8f133cc7e19f15fc1c174b282104bfaf8af0373f960f969'),
