    SourceStratagemActivationProfile('phase17s:stratagem:world-eaters:berzerker-warband:000008431007', 'stratagem:world-eaters:berzerker-warband:000008431007', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:world-eaters:berzerker-warband:000008431007', 'world-eaters', 'berzerker-warband', '000008431007', 'BERZERKER\u2019S WRATH', 1, 'strategic_ploy', "Your opponent's Shooting phase, just after an enemy unit has shot.", 'One Khorne Berzerkers unit from your army that can make a Blood Surge move as a result of those attacks.', 'Do not roll a D6 to determine how far models in your unit can move when they make their Blood Surge move. Instead, when making their Blood Surge move, these models can move up to 8".', 'matched play same stratagem per phase', 'just_after_enemy_unit_has_shot', ('shooting',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), '89796798a812b38b2502fee4b4c84dcc0abf9b7cb8ca3947399a549a5ebb527b'),
    SourceStratagemActivationProfile('phase17s:stratagem:world-eaters:cult-of-blood:000010075002', 'stratagem:world-eaters:cult-of-blood:000010075002', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:world-eaters:cult-of-blood:000010075002', 'world-eaters', 'cult-of-blood', '000010075002', 'BLOODY VENGEANCE', 1, 'epic_deed', 'Any phase.', 'One World Eaters Monster or World Eaters Titanic unit from your army that was just destroyed by an enemy unit. You can use this Stratagem on that unit even though it was just destroyed.', 'Until the end of the battle, each time a model in a Jakhals or Goremongers unit from your army makes an attack that targets the enemy unit that just destroyed your unit, you can re-roll the Hit roll.', 'matched play same stratagem per phase', 'start_phase', ('any',), 'friendly_unit', 'friendly_unit', ('MONSTER', 'TITANIC',), (), (), (), (), 'a56adf4931cc92045eec93cf0a82a9810439306e669239b50e695c721f829a31'),
