    SourceStratagemActivationProfile('phase17s:stratagem:world-eaters:khorne-daemonkin:000010079002', 'stratagem:world-eaters:khorne-daemonkin:000010079002', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:world-eaters:khorne-daemonkin:000010079002', 'world-eaters', 'khorne-daemonkin', '000010079002', 'SUMMONED BY SLAUGHTER', 1, 'strategic_ploy', 'Any phase, when the last model in a unit is destroyed, before removing it from play. (If that unit is a Transport, any units embarked within that TRANSPORT model must disembark first.)', 'One Bloodletters unit from your army that is in Reserves.', 'Set your unit up anywhere on the battlefield wholly within 9" of that destroyed model and more than 6" horizontally away from all enemy units, then remove the destroyed model from play. RESTRICTIONS: You cannot use this Stratagem more than once per battle round.', 'matched play same stratagem per phase', 'start_phase', ('any',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), '3ca7a9125ef6cdabb9169f2e7c1122e7428e6c5b98f2f6315783df26397c58d3'),
    SourceStratagemActivationProfile('phase17s:stratagem:world-eaters:khorne-daemonkin:000010079003', 'stratagem:world-eaters:khorne-daemonkin:000010079003', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:world-eaters:khorne-daemonkin:000010079003', 'world-eaters', 'khorne-daemonkin', '000010079003', 'DAEMONIC FURY', 1, 'battle_tactic', 'Start of your Fight phase.', 'One Blood Legions unit from your army.', 'Select one friendly World Eaters unit within 6" of your unit. Until the end of the turn, melee weapons equipped by models in your WORLD EATERS unit have the [LANCE] ability. If the Daemonic Rage ability is active for your army, then until the end of the phase those melee weapons also have the [TWIN-LINKED] ability.', 'matched play same stratagem per phase', 'start_phase', ('fight',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), '7e2d2fb4277b4e5e358cea0dbdf3bf9d0511e044876e519e70c4d97b6eac437b'),
