    SourceStratagemActivationProfile('phase17s:stratagem:world-eaters:khorne-daemonkin:000010079005', 'stratagem:world-eaters:khorne-daemonkin:000010079005', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:world-eaters:khorne-daemonkin:000010079005', 'world-eaters', 'khorne-daemonkin', '000010079005', 'BLESSING OF BURNING BLOOD', 1, 'battle_tactic', "Your opponent's Shooting phase or the Fight phase, just after an enemy unit has selected its targets.", 'One Blood Legions unit from your army that is within 6" of a friendly World Eaters unit that was selected as the target as one or more of the attacking unit\'s attacks.', 'Until the end of the phase, models in your WORLD EATERS unit have a 5+ invulnerable save. If the Boon of Blood ability is active for your army, then until the end of the phase, models in your WORLD EATERS unit have a 4+ invulnerable save.', 'matched play same stratagem per phase', 'after_unit_selected_as_target', ('shooting', 'fight',), 'friendly_unit', 'selected_target_unit', (), (), (), (), (), 'bf603ff368f1b55e692e94e415fbfd94dd9f81e9f48d0091c8217e1e99c1cf68'),
    SourceStratagemActivationProfile('phase17s:stratagem:world-eaters:khorne-daemonkin:000010079006', 'stratagem:world-eaters:khorne-daemonkin:000010079006', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:world-eaters:khorne-daemonkin:000010079006', 'world-eaters', 'khorne-daemonkin', '000010079006', 'DAEMONTIDE', 1, 'strategic_ploy', 'Your Command phase.', 'One World Eaters unit from your army.', 'Select one friendly Blood Legions unit within 6" of your unit. One destroyed Mounted model, up to D3 destroyed Beast models, or up to D6 destroyed Infantry models are returned to that BLOOD LEGIONS unit with their full wounds remaining. RESTRICTIONS: This Stratagem cannot be used to return destroyed Character models to Attached units.', 'matched play same stratagem per phase', 'start_phase', ('command',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), 'f2153a3b237d1961eb3edee5a80807efface7d46558ca40dd850facfad3ade6b'),
    SourceStratagemActivationProfile('phase17s:stratagem:world-eaters:khorne-daemonkin:000010079007', 'stratagem:world-eaters:khorne-daemonkin:000010079007', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:world-eaters:khorne-daemonkin:000010079007', 'world-eaters', 'khorne-daemonkin', '000010079007', 'MURDER-CALL', 1, 'strategic_ploy', "End of your opponent's Fight phase.", 'One Blood Legions unit from your army that is on the battlefield and not within Engagement Range of one or more enemy units.', 'Remove your unit from the battlefield and place it into Strategic Reserves.', 'matched play same stratagem per phase', 'end_phase', ('fight',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), '3d43d3946f5a7d47131062a457d6f0d620590b2e808336c49de77efdd591944c'),
    SourceStratagemActivationProfile('phase17s:stratagem:world-eaters:possessed-slaughterband:000010083002', 'stratagem:world-eaters:possessed-slaughterband:000010083002', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:world-eaters:possessed-slaughterband:000010083002', 'world-eaters', 'possessed-slaughterband', '000010083002', 'DAEMONIC RESISTANCE', 2, 'battle_tactic', "Your opponent's Shooting phase or the Fight phase, just after an enemy unit has selected its targets.", "One World Eaters Possessed unit from your army that was selected as the target of one or more of the attacking unit's attacks.", 'Until the end of the phase, each time an attack targets your unit, subtract 1 from the Wound roll.', 'matched play same stratagem per phase', 'after_unit_selected_as_target', ('shooting', 'fight',), 'friendly_unit', 'selected_target_unit', (), (), (), (), (), 'cceacfdae19fd2d5d13315f8ecf96f879dc62529bf0693c78722fa2520bfd582'),
    SourceStratagemActivationProfile('phase17s:stratagem:world-eaters:possessed-slaughterband:000010083003', 'stratagem:world-eaters:possessed-slaughterband:000010083003', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:world-eaters:possessed-slaughterband:000010083003', 'world-eaters', 'possessed-slaughterband', '000010083003', 'DAEMONIC STRENGTH', 1, 'battle_tactic', 'Fight phase.', 'One World Eaters Possessed unit from your army that has not been selected to fight this phase.', 'Until the end of the phase, each time an attack made by a model in your unit is allocated to an enemy model, if your unit has the Eightbound keyword and that enemy model is not a MONSTER or VEHICLE, add 1 to the Damage characteristic of that attack. If your unit has the Exalted Eightbound keyword and that enemy model is a MONSTER or VEHICLE, add 1 to the Damage characteristic of that attack instead.', 'matched play same stratagem per phase', 'start_phase', ('fight',), 'friendly_unit', 'not_selected_to_fight_unit', (), (), (), (), (), '1d942a38836c40536f6e198e85e0f7bf217acef8ae118df7e2274dd90a669605'),
    SourceStratagemActivationProfile('phase17s:stratagem:world-eaters:possessed-slaughterband:000010083004', 'stratagem:world-eaters:possessed-slaughterband:000010083004', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:world-eaters:possessed-slaughterband:000010083004', 'world-eaters', 'possessed-slaughterband', '000010083004', 'IMMORTAL FURY', 2, 'battle_tactic', 'Fight phase, just after an enemy unit has selected its targets.', "One World Eaters Possessed unit from your army that was selected as the target of one or more of the attacking unit's attacks.", "Until the end of the phase, each time a model in your unit is destroyed, if that model has not fought this phase, do not remove it from play. The destroyed model can fight after the attacking model's unit has finished making its attacks, and is then removed from play.", 'matched play same stratagem per phase', 'after_unit_selected_as_target', ('fight',), 'friendly_unit', 'selected_target_unit', (), (), (), (), (), 'e79834a0a05840f92cfefeedde5601b296937164650fe5fc50f47f7ca881990e'),
    SourceStratagemActivationProfile('phase17s:stratagem:world-eaters:possessed-slaughterband:000010083005', 'stratagem:world-eaters:possessed-slaughterband:000010083005', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:world-eaters:possessed-slaughterband:000010083005', 'world-eaters', 'possessed-slaughterband', '000010083005', 'RAPID MANIFESTATION', 1, 'strategic_ploy', 'Your Movement phase.', 'One Exalted Eightbound unit from your army that is arriving using the Deep Strike ability this phase.', 'Your unit can be set up anywhere on the battlefield that is more than 6" horizontally away from all enemy units. RESTRICTIONS: A unit targeted with this Stratagem is not eligible to declare a charge in the same turn.', 'matched play same stratagem per phase', 'start_phase', ('movement',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), '1f0bb560f15cc6e3ffed1c5abac30eb099373958af4e75c598e3df4b872e7f4f'),
    SourceStratagemActivationProfile('phase17s:stratagem:world-eaters:possessed-slaughterband:000010083006', 'stratagem:world-eaters:possessed-slaughterband:000010083006', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:world-eaters:possessed-slaughterband:000010083006', 'world-eaters', 'possessed-slaughterband', '000010083006', 'WARP STALKERS', 1, 'strategic_ploy', 'Your Movement phase or your Charge phase.', 'One World Eaters Possessed unit from your army that has not been selected to move or declare a charge this phase.', 'Until the end of the phase, each time a model in your unit makes a Normal, Advance, Fall Back or Charge move, it can move through enemy models (excluding MONSTERS and VEHICLES). When doing so, it can move within Engagement Range of such models but, unless that move was a Charge move, it cannot end that move within Engagement Range of them, and any Desperate Escape test is automatically passed.', 'matched play same stratagem per phase', 'start_phase', ('movement', 'charge',), 'friendly_unit', 'selected_to_move_unit', (), (), (), (), (), '27d14e4377b72f2af94cd951c5ca69ae2bc477994035cbe281f4c9188905bd81'),
    SourceStratagemActivationProfile('phase17s:stratagem:world-eaters:possessed-slaughterband:000010083007', 'stratagem:world-eaters:possessed-slaughterband:000010083007', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:world-eaters:possessed-slaughterband:000010083007', 'world-eaters', 'possessed-slaughterband', '000010083007', 'HORRIFYING VIOLENCE', 1, 'strategic_ploy', "Your opponent's Command phase.", 'One World Eaters Possessed unit from your army.', 'Each enemy unit within Engagement Range of your unit must take a Battle-shock test, subtracting 1 from that test.', 'matched play same stratagem per phase', 'start_phase', ('command',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), 'e9ec48d842ca66306ac9a5010f0711ec88746a3ee777c6858fd4b807022ee09e'),
    SourceStratagemActivationProfile('phase17s:stratagem:world-eaters:vessels-of-wrath:000009848002', 'stratagem:world-eaters:vessels-of-wrath:000009848002', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:world-eaters:vessels-of-wrath:000009848002', 'world-eaters', 'vessels-of-wrath', '000009848002', 'ASPIRE TO INFAMY', 1, 'battle_tactic', 'Fight phase.', 'One Khorne Berzerkers or Jakhals unit from your army that has not been selected to fight this phase and is within 8" of one or more friendly World Eaters Character models.', 'Until the end of the phase, improve the Strength and Armour Penetration characteristics of melee weapons equipped by non-CHARACTER models in your unit by 1.', 'matched play same stratagem per phase', 'start_phase', ('fight',), 'friendly_unit', 'not_selected_to_fight_unit', ('CHARACTER',), (), (), (), (), 'b7de4e6a94174ffc33d2a0eea30c41e0d5232fd804387e2cd444373e682dfed7'),
    SourceStratagemActivationProfile('phase17s:stratagem:world-eaters:vessels-of-wrath:000009848003', 'stratagem:world-eaters:vessels-of-wrath:000009848003', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:world-eaters:vessels-of-wrath:000009848003', 'world-eaters', 'vessels-of-wrath', '000009848003', 'OVERSHADOWED BY NONE', 1, 'battle_tactic', 'Fight phase.', 'One World Eaters Infantry, World Eaters Mounted or World Eaters Daemon Prince unit from your army that has not been selected to fight this phase.', 'Until the end of the phase, each time a model in your unit makes an attack that targets a MONSTER or VEHICLE unit, you can re-roll the Wound roll.', 'matched play same stratagem per phase', 'start_phase', ('fight',), 'friendly_unit', 'not_selected_to_fight_unit', ('INFANTRY', 'MOUNTED',), (), (), (), (), 'e49aeb082f46992cd20fa3005bb8ebdd83266dfaabc2b25158d02426aab6d68b'),
    SourceStratagemActivationProfile('phase17s:stratagem:world-eaters:vessels-of-wrath:000009848004', 'stratagem:world-eaters:vessels-of-wrath:000009848004', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:world-eaters:vessels-of-wrath:000009848004', 'world-eaters', 'vessels-of-wrath', '000009848004', 'GORY DEDICATION', 1, 'strategic_ploy', 'End of the Fight phase.', 'One WORLD EATERS unit from your army that destroyed one or more enemy models with a melee attack this phase.', "Select one objective marker you control that your unit is within range of. That objective marker remains under your control until your opponent's Level of Control over that objective marker is greater than yours at the end of a phase.", 'matched play same stratagem per phase', 'end_phase', ('fight',), 'friendly_unit', 'friendly_unit', (), (), (), (), (), '59caea1a507b2999b3a714df699ffdafc2bd34f2c58609e3f48ea5c25781a662'),
    SourceStratagemActivationProfile('phase17s:stratagem:world-eaters:vessels-of-wrath:000009848005', 'stratagem:world-eaters:vessels-of-wrath:000009848005', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:world-eaters:vessels-of-wrath:000009848005', 'world-eaters', 'vessels-of-wrath', '000009848005', 'PUNISH THE CRAVEN', 1, 'strategic_ploy', "Your opponent's Movement phase, just after an enemy unit (excluding MONSTERS and VEHICLES) is selected to Fall Back.", 'One World Eaters Infantry or World Eaters Daemon Prince unit from your army within Engagement Range of that enemy unit.', 'When that enemy unit Falls Back, all models in that enemy unit must take a Desperate Escape test. When doing so, if your unit is a VESSEL OF WRATH unit, subtract 1 from each of those tests.', 'matched play same stratagem per phase', 'just_after_enemy_unit_selected_to_fall_back', ('movement',), 'friendly_unit', 'friendly_unit', ('INFANTRY',), (), (), (), (), '9da001f2fd2d0a87e8538506c4aaafaceefa3e4bf185a1b6f92c1d3494be88ac'),
    SourceStratagemActivationProfile('phase17s:stratagem:world-eaters:vessels-of-wrath:000009848006', 'stratagem:world-eaters:vessels-of-wrath:000009848006', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:world-eaters:vessels-of-wrath:000009848006', 'world-eaters', 'vessels-of-wrath', '000009848006', 'MEET FORCE WITH FORCE', 1, 'strategic_ploy', "Your opponent's Shooting phase, just after an enemy unit has shot.", 'One World Eaters Infantry, World Eaters Mounted or World Eaters Daemon Prince unit from your army that lost one or more wounds as a result of those attacks.', 'Your unit can make a Blood Surge move. To do so, roll one D6: models in your unit move a number of inches up to the result, but your unit must end that move as close as possible to the closest enemy unit (excluding AIRCRAFT). When doing so, those models can be moved within Engagement Range of that enemy unit. If your unit is a Khorne Berzerkers or VESSEL OF WRATH unit, you can re-roll the D6 to determine how far your unit can move.', 'matched play same stratagem per phase', 'just_after_enemy_unit_has_shot', ('shooting',), 'friendly_unit', 'friendly_unit', ('INFANTRY', 'MOUNTED',), (), (), (), (), '1c4194e06c604c4f800bf6f059796bd86da06a3885c6b0e30e4a184a74bd98c2'),
    SourceStratagemActivationProfile('phase17s:stratagem:world-eaters:vessels-of-wrath:000009848007', 'stratagem:world-eaters:vessels-of-wrath:000009848007', 'gw-11e-phase17e-exact-faction-subrules-2026-27:stratagem:world-eaters:vessels-of-wrath:000009848007', 'world-eaters', 'vessels-of-wrath', '000009848007', 'BRAZEN CONTEMPT', 1, 'battle_tactic', "Your opponent's Shooting phase, just after an enemy unit has selected its targets.", "One WORLD EATERS unit from your army that was selected as the target of one or more of the attacking unit's attacks.", 'Until the end of the phase, each time an attack targets your unit, if the Strength characteristic of that attack is greater than the Toughness characteristic of your unit, subtract 1 from the Wound roll, or, if it is a VESSEL OF WRATH unit, subtract 1 from the Wound roll instead.', 'matched play same stratagem per phase', 'after_unit_selected_as_target', ('shooting',), 'friendly_unit', 'selected_target_unit', (), (), (), (), (), '8874a0c9e68e1a8da34ddff36a3dbf42d8c42a2800df9878114e16b34747fa9f'),
